112→func buildPromptContext(s *sessionStatus) string {
113→	var b strings.Builder
114→
115→	if !s.configLoaded || !s.setupCompleted {
116→		b.WriteString("You are in a Nurge workspace. Setup is not complete. ")
117→		b.WriteString("Guide the user to run /nurge:setup to finish configuration. ")
118→		b.WriteString("Do not attempt to use nurge data commands — they will have no data yet.")
119→		return b.String()
120→	}
121→
122→	// User context
123→	name := s.settings["user.name"]
124→	role := s.settings["user.role"]
125→	if name != "" {
126→		fmt.Fprintf(&b, "User: %s", name)
127→		if role != "" {
128→			fmt.Fprintf(&b, " (%s)", role)
129→		}
130→		b.WriteString("\n")
131→	}
132→
133→	b.WriteString("You are in a Nurge outbound sales workspace.\n")
134→	fmt.Fprintf(&b, "Status: Setup complete. %s emails synced (%d outbound). %d contacts. %d skills active.\n",
135→		formatCount(s.emailTotal), s.outboundTotal, s.contactCount, s.skillCount)
136→
137→	// Pipeline state for LLM context
138→	if ps := s.pipelineStatus; ps != nil {
139→		fmt.Fprintf(&b, "Pipeline state: sourced=%d researched=%d ready=%d contacted=%d replied=%d\n",
140→			ps.Pipeline.Sourced, ps.Pipeline.Researched, ps.Pipeline.Ready,
141→			ps.Pipeline.Contacted, ps.Pipeline.Replied)
142→		fmt.Fprintf(&b, "Today: %d/%d first touches sent, %d follow-ups sent, %d follow-ups due\n",
143→			ps.NewOutreach.SentToday, ps.NewOutreach.DailyLimit,
144→			ps.FollowUps.SentToday, ps.FollowUps.DueToday)
145→		if ps.Nudge != nil && ps.Nudge.Type != "healthy" {
146→			fmt.Fprintf(&b, "PIPELINE NUDGE [%s]: %s\n", ps.Nudge.Type, ps.Nudge.Message)
147→			if ps.Nudge.Action != "" {
148→				fmt.Fprintf(&b, "Suggested action: %s\n", ps.Nudge.Action)
149→			}
150→		}

