 10→// DistillResult summarizes the outcome of distilling raw learnings into
 11→// knowledge atom updates and strategic memory entries.
 12→type DistillResult struct {
 13→	LearningsProcessed int      `json:"learnings_processed"`
 14→	AtomsUpdated       int      `json:"atoms_updated"`
 15→	AtomsCreated       int      `json:"atoms_created"`
 16→	Categories         []string `json:"categories"`
 17→}
 18→
 19→// learningTypeToAtomTypes maps learning types to the knowledge atom types they
 20→// should be appended to.
 21→var learningTypeToAtomTypes = map[string][]string{
 22→	"tone":       {"tone"},
 23→	"icp":        {"personas", "positioning"},
 24→	"product":    {"positioning"},
 25→	"pattern":    {"hooks", "tone"},
 26→	"preference": {}, // preferences are context-dependent; handled specially
 27→}
 28→
 29→// Distill processes undistilled learnings, appending them to the relevant
 30→// knowledge atoms and strategic memory entries, then marks them as distilled.
 31→//
 32→// The operation is mechanical: learning content is appended to a "learnings"
 33→// array inside each matching atom's JSON content. This preserves the original
 34→// atom content while accumulating session insights.
 35→func Distill(db *sql.DB) (*DistillResult, error) {
 36→	result := &DistillResult{}
 37→
 38→	// 1. Load undistilled learnings
 39→	learnings, err := listUndistilledLearnings(db)
 40→	if err != nil {
 41→		return nil, fmt.Errorf("loading undistilled learnings: %w", err)
 42→	}
 43→	if len(learnings) == 0 {
 44→		return result, nil
 45→	}
 46→
 47→	// 2. Group by type
 48→	groups := map[string][]Learning{}
 49→	for _, l := range learnings {
 50→		groups[l.Type] = append(groups[l.Type], l)
 51→	}
 52→
 53→	// 3. Process each group
 54→	categorySet := map[string]bool{}
 55→	for typ, items := range groups {
 56→		categorySet[typ] = true
 57→
 58→		switch typ {
 59→		case "competitor":
 60→			// Competitors go to strategic memory
 61→			for _, l := range items {
 62→				if err := saveCompetitorMemory(db, l); err != nil {
 63→					return nil, fmt.Errorf("saving competitor memory: %w", err)
 64→				}
 65→			}
 66→
 67→		case "preference":
 68→			// Preferences: try to match to relevant atom types based on content keywords
 69→			for _, l := range items {
 70→				atomTypes := inferAtomTypesFromPreference(l.Content)
 71→				for _, atomType := range atomTypes {
 72→					created, err := appendLearningToAtoms(db, atomType, l)
 73→					if err != nil {
 74→						return nil, fmt.Errorf("appending preference to %s atoms: %w", atomType, err)
 75→					}
 76→					if created {
 77→						result.AtomsCreated++
 78→					} else {
 79→						result.AtomsUpdated++
 80→					}
 81→				}
 82→			}
 83→
 84→		default:
 85→			// Standard mapping: tone, icp, product, pattern
 86→			atomTypes, ok := learningTypeToAtomTypes[typ]
 87→			if !ok {
 88→				// Unknown type — skip but still mark as distilled
 89→				continue
 90→			}
 91→			for _, atomType := range atomTypes {
 92→				for _, l := range items {
 93→					created, err := appendLearningToAtoms(db, atomType, l)
 94→					if err != nil {
 95→						return nil, fmt.Errorf("appending %s learning to %s atoms: %w", typ, atomType, err)
 96→					}
 97→					if created {
 98→						result.AtomsCreated++
 99→					} else {
100→						result.AtomsUpdated++

