 73→func printDone(name string) {
 74→	fmt.Fprintf(os.Stdout, "  \033[32m✓\033[0m %s\n", name)
 75→}
 76→
 77→func printSkip(name string) {
 78→	fmt.Fprintf(os.Stdout, "  \033[32m✓\033[0m %s (already done)\n", name)
 79→}
 80→
 81→func printFail(name string, err error) {
 82→	fmt.Fprintf(os.Stderr, "  \033[31m✗\033[0m %s: %v\n", name, err)
 83→}
