219→	recipients := append(parseRecipients(e.ToEmails), parseRecipients(e.CcEmails)...)
220→	for _, recipient := range recipients {
221→		if err := upsertContact(d, source, recipient, timestamp, incrementCount); err != nil {
222→			return err
223→		}
224→	}
225→	return nil
226→}
227→
228→func upsertContact(d *sql.DB, source, emailAddress, activityAt string, incrementCount bool) error {
229→	emailAddress = strings.ToLower(strings.TrimSpace(emailAddress))
230→	if emailAddress == "" {
231→		return nil
232→	}
233→	domain := ""
234→	parts := strings.SplitN(emailAddress, "@", 2)
235→	if len(parts) == 2 {
236→		domain = parts[1]
237→	}
238→
239→	_, err := d.Exec(`
240→		INSERT INTO contacts (id, source, email, domain, last_activity_at, email_count, last_emailed_at)
241→		VALUES (?, ?, ?, ?, ?, 1, ?)
242→		ON CONFLICT(source, email) DO UPDATE SET
243→			domain = CASE WHEN excluded.domain != '' THEN excluded.domain ELSE contacts.domain END,
244→			last_activity_at = CASE
245→				WHEN contacts.last_activity_at = '' OR contacts.last_activity_at IS NULL OR excluded.last_activity_at > contacts.last_activity_at THEN excluded.last_activity_at
246→				ELSE contacts.last_activity_at
247→			END,
248→			last_emailed_at = CASE
249→				WHEN contacts.last_emailed_at = '' OR contacts.last_emailed_at IS NULL OR excluded.last_emailed_at > contacts.last_emailed_at THEN excluded.last_emailed_at
250→				ELSE contacts.last_emailed_at
251→			END,
252→			email_count = contacts.email_count + ?,
253→			updated_at = datetime('now')`,
254→		"contact:"+source+":"+emailAddress, source, emailAddress, domain, activityAt, activityAt, boolToInt(incrementCount),
255→	)
256→	return err
257→}
258→
259→func boolToInt(value bool) int {
260→	if value {
261→		return 1
262→	}
263→	return 0
264→}
265→
266→func extractEmail(header string) string {
267→	if i := strings.Index(header, "<"); i != -1 {
268→		if j := strings.Index(header, ">"); j != -1 {
269→			return header[i+1 : j]
270→		}
271→	}
272→	return strings.TrimSpace(header)
273→}
274→
275→func emailsToJSON(header string) string {
276→	if header == "" {
277→		return "[]"
278→	}
279→	parts := strings.Split(header, ",")
280→	emails := make([]string, 0, len(parts))
281→	for _, p := range parts {
282→		emails = append(emails, extractEmail(p))
283→	}
284→	data, _ := json.Marshal(emails)
285→	return string(data)
286→}
