  1→package session
  2→
  3→import (
  4→	"database/sql"
  5→	"encoding/json"
  6→	"fmt"
  7→	"strings"
  8→)
  9→
 10→// DistillResult summarizes the outcome of distilling raw learnings into
 11→// knowledge atom updates and strategic memory entries.
 12→type DistillResult struct {
 13→	LearningsProcessed int      `json:"learnings_processed"`
 14→	AtomsUpdated       int      `json:"atoms_updated"`
 15→	AtomsCreated       int      `json:"atoms_created"`
 16→	Categories         []string `json:"categories"`
 17→}
 18→
 19→// learningTypeToAtomTypes maps learning types to the knowledge atom types they
 20→// should be appended to.
 21→var learningTypeToAtomTypes = map[string][]string{
 22→	"tone":       {"tone"},
 23→	"icp":        {"personas", "positioning"},
 24→	"product":    {"positioning"},
 25→	"pattern":    {"hooks", "tone"},
 26→	"preference": {}, // preferences are context-dependent; handled specially
 27→}
 28→
 29→// Distill processes undistilled learnings, appending them to the relevant
 30→// knowledge atoms and strategic memory entries, then marks them as distilled.
 31→//
 32→// The operation is mechanical: learning content is appended to a "learnings"
 33→// array inside each matching atom's JSON content. This preserves the original
 34→// atom content while accumulating session insights.
 35→func Distill(db *sql.DB) (*DistillResult, error) {
 36→	result := &DistillResult{}
 37→
 38→	// 1. Load undistilled learnings
 39→	learnings, err := listUndistilledLearnings(db)
 40→	if err != nil {
 41→		return nil, fmt.Errorf("loading undistilled learnings: %w", err)
 42→	}
 43→	if len(learnings) == 0 {
 44→		return result, nil
 45→	}
 46→
 47→	// 2. Group by type
 48→	groups := map[string][]Learning{}
 49→	for _, l := range learnings {
 50→		groups[l.Type] = append(groups[l.Type], l)
 51→	}
 52→
 53→	// 3. Process each group
 54→	categorySet := map[string]bool{}
 55→	for typ, items := range groups {
 56→		categorySet[typ] = true
 57→
 58→		switch typ {
 59→		case "competitor":
 60→			// Competitors go to strategic memory
 61→			for _, l := range items {
 62→				if err := saveCompetitorMemory(db, l); err != nil {
 63→					return nil, fmt.Errorf("saving competitor memory: %w", err)
 64→				}
 65→			}
 66→
 67→		case "preference":
 68→			// Preferences: try to match to relevant atom types based on content keywords
 69→			for _, l := range items {
 70→				atomTypes := inferAtomTypesFromPreference(l.Content)
 71→				for _, atomType := range atomTypes {
 72→					created, err := appendLearningToAtoms(db, atomType, l)
 73→					if err != nil {
 74→						return nil, fmt.Errorf("appending preference to %s atoms: %w", atomType, err)
 75→					}
 76→					if created {
 77→						result.AtomsCreated++
 78→					} else {
 79→						result.AtomsUpdated++
 80→					}
 81→				}
 82→			}
 83→
 84→		default:
 85→			// Standard mapping: tone, icp, product, pattern
 86→			atomTypes, ok := learningTypeToAtomTypes[typ]
 87→			if !ok {
 88→				// Unknown type — skip but still mark as distilled
 89→				continue
 90→			}
 91→			for _, atomType := range atomTypes {
 92→				for _, l := range items {
 93→					created, err := appendLearningToAtoms(db, atomType, l)
 94→					if err != nil {
 95→						return nil, fmt.Errorf("appending %s learning to %s atoms: %w", typ, atomType, err)
 96→					}
 97→					if created {
 98→						result.AtomsCreated++
 99→					} else {
100→						result.AtomsUpdated++
101→					}
102→				}
103→			}
104→		}
105→	}
106→
107→	// 4. Mark all as distilled
108→	ids := make([]int, len(learnings))
109→	for i, l := range learnings {
110→		ids[i] = l.ID
111→	}
112→	if err := markDistilled(db, ids); err != nil {
113→		return nil, fmt.Errorf("marking learnings as distilled: %w", err)
114→	}
115→
116→	result.LearningsProcessed = len(learnings)
117→	for cat := range categorySet {
118→		result.Categories = append(result.Categories, cat)
119→	}
120→
121→	return result, nil
122→}
123→
124→// listUndistilledLearnings returns learnings that have not yet been distilled.
125→func listUndistilledLearnings(db *sql.DB) ([]Learning, error) {
126→	rows, err := db.Query(`
127→		SELECT id, type, content, source_session, created_at
128→		FROM learnings
129→		WHERE distilled_at IS NULL OR distilled_at = ''
130→		ORDER BY created_at ASC`)
131→	if err != nil {
132→		return nil, err
133→	}
134→	defer rows.Close()
135→
136→	var learnings []Learning
137→	for rows.Next() {
138→		var l Learning
139→		if err := rows.Scan(&l.ID, &l.Type, &l.Content, &l.SourceSession, &l.CreatedAt); err != nil {
140→			return nil, err
141→		}
142→		learnings = append(learnings, l)
143→	}
144→	return learnings, rows.Err()
145→}
146→
147→// markDistilled sets the distilled_at timestamp for the given learning IDs.
148→func markDistilled(db *sql.DB, ids []int) error {
149→	if len(ids) == 0 {
150→		return nil
151→	}
152→
153→	// Build batch update with placeholders
154→	placeholders := make([]string, len(ids))
155→	args := make([]any, len(ids))
156→	for i, id := range ids {
157→		placeholders[i] = "?"
158→		args[i] = id
159→	}
160→
161→	query := fmt.Sprintf(
162→		"UPDATE learnings SET distilled_at = datetime('now'), updated_at = datetime('now') WHERE id IN (%s)",
163→		strings.Join(placeholders, ","),
164→	)
165→	_, err := db.Exec(query, args...)
166→	return err
167→}
168→
169→// appendLearningToAtoms finds atoms of the given type and appends the learning
170→// content to a "learnings" array in each atom's JSON content.
171→//
172→// If no atoms of the type exist, one is created with the global (empty) scope.
173→// Returns true if a new atom was created.
174→func appendLearningToAtoms(db *sql.DB, atomType string, learning Learning) (bool, error) {
175→	// Find existing atoms of this type
176→	rows, err := db.Query(
177→		`SELECT id, content FROM knowledge_atoms WHERE atom_type = ?`,
178→		atomType,
179→	)
180→	if err != nil {
181→		return false, err
182→	}
183→	defer rows.Close()
184→
185→	var found bool
186→	for rows.Next() {
187→		found = true
188→		var id int
189→		var content string
190→		if err := rows.Scan(&id, &content); err != nil {
191→			return false, err
192→		}
193→
194→		updated, err := appendLearningToJSON(content, learning)
195→		if err != nil {
196→			return false, err
197→		}
198→
199→		_, err = db.Exec(
200→			`UPDATE knowledge_atoms SET content = ?, updated_at = datetime('now') WHERE id = ?`,
201→			updated, id,
202→		)
203→		if err != nil {
204→			return false, fmt.Errorf("updating atom %d: %w", id, err)
205→		}
206→	}
207→	if err := rows.Err(); err != nil {
208→		return false, err
209→	}
210→
211→	if found {
212→		return false, nil
213→	}
214→
215→	// No atoms of this type exist — create a new one with global scope
216→	initial := map[string]any{
217→		"learnings": []map[string]string{
218→			{
219→				"type":       learning.Type,
220→				"content":    learning.Content,
221→				"created_at": learning.CreatedAt,
222→			},
223→		},
224→	}
225→	initialJSON, err := json.Marshal(initial)
226→	if err != nil {
227→		return false, err
228→	}
229→
230→	_, err = db.Exec(
231→		`INSERT INTO knowledge_atoms (atom_type, scope, content, source, confidence) VALUES (?, '', ?, 'distill', 0.8)`,
232→		atomType, string(initialJSON),
233→	)
234→	if err != nil {
235→		return false, fmt.Errorf("creating atom for type %s: %w", atomType, err)
236→	}
237→	return true, nil
238→}
239→
240→// appendLearningToJSON takes existing atom JSON content and appends a learning
241→// entry to the "learnings" array within it.
242→func appendLearningToJSON(existingContent string, learning Learning) (string, error) {
243→	var data map[string]any
244→	if err := json.Unmarshal([]byte(existingContent), &data); err != nil {
245→		// If existing content isn't a JSON object, wrap it
246→		data = map[string]any{
247→			"original": existingContent,
248→		}
249→	}
250→
251→	// Get or create the learnings array
252→	var learnings []any
253→	if existing, ok := data["learnings"]; ok {
254→		if arr, ok := existing.([]any); ok {
255→			learnings = arr
256→		}
257→	}
258→
259→	// Append the new learning
260→	learnings = append(learnings, map[string]string{
261→		"type":       learning.Type,
262→		"content":    learning.Content,
263→		"created_at": learning.CreatedAt,
264→	})
265→	data["learnings"] = learnings
266→
267→	result, err := json.Marshal(data)
268→	if err != nil {
269→		return "", err
270→	}
271→	return string(result), nil
272→}
