274→// saveCompetitorMemory stores a competitor learning as strategic memory.
275→func saveCompetitorMemory(db *sql.DB, learning Learning) error {
276→	return SaveStrategicMemory(db, StrategicMemoryInput{
277→		Category:       "competitor_intel",
278→		Summary:        learning.Content,
279→		AffectedSkills: []string{"nurge-outbound", "nurge-research", "nurge-qualify"},
280→		Source:         "learning_distill",
281→		SourceKey:      fmt.Sprintf("competitor_learning_%d", learning.ID),
282→		Priority:       1,
283→	})
284→}
285→
286→// inferAtomTypesFromPreference guesses which atom types a preference learning
287→// should be appended to, based on content keywords.
288→func inferAtomTypesFromPreference(content string) []string {
289→	lower := strings.ToLower(content)
290→	var types []string
291→
292→	if strings.Contains(lower, "tone") || strings.Contains(lower, "voice") || strings.Contains(lower, "casual") || strings.Contains(lower, "formal") || strings.Contains(lower, "salesy") {
293→		types = append(types, "tone")
294→	}
295→	if strings.Contains(lower, "subject") || strings.Contains(lower, "hook") || strings.Contains(lower, "opening") {
296→		types = append(types, "hooks")
297→	}
298→	if strings.Contains(lower, "structure") || strings.Contains(lower, "format") || strings.Contains(lower, "length") || strings.Contains(lower, "short") || strings.Contains(lower, "long") {
299→		types = append(types, "tone")
300→	}
301→	if strings.Contains(lower, "position") || strings.Contains(lower, "product") || strings.Contains(lower, "pricing") || strings.Contains(lower, "value") {
302→		types = append(types, "positioning")
303→	}
304→	if strings.Contains(lower, "persona") || strings.Contains(lower, "icp") || strings.Contains(lower, "target") || strings.Contains(lower, "audience") {
305→		types = append(types, "personas")
306→	}
307→
308→	// If no match, default to tone (most common preference type)
309→	if len(types) == 0 {
310→		types = append(types, "tone")
311→	}
312→	return types
313→}
