 16→// runSessionStart outputs JSON with systemMessage (visible banner) and
 17→// additionalContext (LLM context) for the SessionStart hook.
 18→// Also captures the session in DB + log.
 19→func runSessionStart() error {
 20→	// Read stdin (Claude Code sends session info)
 21→	input, _ := session.ReadStdin()
 22→
 23→	// Sync permissions — ensures existing users get any new permissions
 24→	// added in later versions. Graceful — never fails the hook.
 25→	project.SyncPermissions()
 26→
 27→	syncReport := attemptSessionStartSync()
 28→
 29→	// Auto-update check (non-blocking, cached)
 30→	updateMsg := checkAndAutoUpdate()
 31→
 32→	s := gatherStatus()
 33→	s.startSync = syncReport
 34→
 35→	// Capture session + sync event in a single DB open (graceful — don't fail the hook)
 36→	if input != nil && input.SessionID != "" && db.Exists() {
 37→		if d, err := db.Open(); err == nil {
 38→
 39→			session.CreateSession(d, input.SessionID, input.Model, input.Source, input.TranscriptPath)
 40→			session.AddEvent(d, input.SessionID, "session_start", input)
 41→			if syncReport != nil && syncReport.Attempted {
 42→				session.AddEvent(d, input.SessionID, "sync_pull", syncReport)
 43→			}
 44→			d.Close()
 45→		}
 46→		session.Logger().Info("session-start", "session_id", input.SessionID, "model", input.Model)
 47→		session.FlushLog()
 48→	}
 49→
 50→	banner := buildBanner(s)
 51→	if updateMsg != "" {
 52→		banner += "\n  " + updateMsg
 53→	}
 54→	context := buildPromptContext(s)
 55→
 56→	out := hookOutput{
 57→		SystemMessage: banner,
 58→		HookSpecificOut: &hookSpecificOut{
 59→			HookEventName:     "SessionStart",
 60→			AdditionalContext: context,
 61→		},
 62→	}
 63→
 64→	enc := json.NewEncoder(os.Stdout)
 65→	return enc.Encode(out)
 66→}
 67→
 68→// openSessionDB reads hook stdin, opens the DB, and ensures session tables.
 69→// Returns (nil, nil, nil) when the hook should silently no-op.
 70→func openSessionDB() (*sql.DB, *session.HookInput, error) {
 71→	input, err := session.ReadStdin()
 72→	if err != nil || input == nil || input.SessionID == "" {
 73→		return nil, nil, nil
 74→	}
 75→	if !db.Exists() {
 76→		return nil, nil, nil
 77→	}
 78→	d, err := db.Open()
 79→	if err != nil {
 80→		return nil, nil, nil
 81→	}
 82→	return d, input, nil
 83→}
 84→
 85→// runUserPrompt captures a user prompt submission event.
 86→func runUserPrompt() error {
 87→	d, input, _ := openSessionDB()
 88→	if d == nil {
 89→		return nil
 90→	}
 91→	defer d.Close()
 92→
 93→	session.AddEvent(d, input.SessionID, "prompt", input)
 94→	session.Logger().Info("prompt", "session_id", input.SessionID)
 95→	session.FlushLog()
 96→	return nil
 97→}
 98→
 99→// runStop captures a stop event and creates a checkpoint.
100→func runStop() error {
101→	d, input, _ := openSessionDB()
102→	if d == nil {
103→		return nil
104→	}
105→	defer d.Close()
106→
107→	session.AddEvent(d, input.SessionID, "stop", input)
108→	if len(input.ModifiedFiles) > 0 {
109→		session.AddCheckpoint(d, input.SessionID, input.ModifiedFiles)
110→	}
111→
112→	session.Logger().Info("stop", "session_id", input.SessionID, "reason", input.StopReason)
113→	session.FlushLog()
114→	return nil
115→}
116→
117→// runSessionEnd marks a session as ended.
118→func runSessionEnd() error {
119→	d, input, _ := openSessionDB()
120→	if d == nil {
121→		return nil
122→	}
123→	defer d.Close()
124→
125→	session.EndSession(d, input.SessionID)
126→	session.AddEvent(d, input.SessionID, "session_end", input)
127→
128→	pushReport := attemptSessionEndPush(d)
129→	if pushReport.Attempted {
130→		session.AddEvent(d, input.SessionID, "sync_push", pushReport)
131→		if pushReport.Error != "" {
132→			session.Logger().Info("session-sync-push", "session_id", input.SessionID, "error", pushReport.Error)
133→		} else {
134→			session.Logger().Info("session-sync-push", "session_id", input.SessionID, "rows_pushed", pushReport.RowsPushed)
135→		}
136→	}
137→
138→	session.Logger().Info("session-end", "session_id", input.SessionID)
139→	session.FlushLog()
140→	return nil
141→}
