237→func buildSyncBannerLine(report *sessionSyncReport) string {
238→	if report == nil || !report.Attempted {
239→		return ""
240→	}
241→	if report.Error != "" {
242→		return "Remote sync unavailable — using last local state"
243→	}
244→	if report.RowsUpserted == 0 {
245→		return ""
246→	}
247→
248→	parts := []string{}
249→	if report.Delta != nil {
250→		if report.Delta.TasksSent > 0 {
251→			parts = append(parts, fmt.Sprintf("%d follow-up%s sent", report.Delta.TasksSent, pluralSuffix(report.Delta.TasksSent)))
252→		}
253→		if report.Delta.RepliesNeedingAttention > 0 {
254→			parts = append(parts, fmt.Sprintf("%d repl%s need attention", report.Delta.RepliesNeedingAttention, pluralSuffix(report.Delta.RepliesNeedingAttention, "y", "ies")))
255→		}
256→		if report.Delta.TasksFailed > 0 {
257→			parts = append(parts, fmt.Sprintf("%d send failure%s", report.Delta.TasksFailed, pluralSuffix(report.Delta.TasksFailed)))
258→		}
259→		if len(report.Delta.AuthExpiredMailboxes) > 0 {
260→			parts = append(parts, fmt.Sprintf("%d mailbox reconnect%s needed", len(report.Delta.AuthExpiredMailboxes), pluralSuffix(len(report.Delta.AuthExpiredMailboxes))))
261→		}
262→	}
263→	if len(parts) == 0 {
264→		return fmt.Sprintf("Synced %d remote update%s", report.RowsUpserted, pluralSuffix(report.RowsUpserted))
265→	}
266→	return "While you were away: " + strings.Join(parts, " | ")
267→}
