269→func buildSyncPromptContext(report *sessionSyncReport) string {
270→	if report == nil || !report.Attempted {
271→		return ""
272→	}
273→
274→	var b strings.Builder
275→	if report.Error != "" {
276→		fmt.Fprintf(&b, "Remote sync status: unavailable (%s). Work from local state and avoid assuming cloud execution has fully caught up.\n", report.Error)
277→		return b.String()
278→	}
279→
280→	if report.RowsUpserted == 0 {
281→		b.WriteString("Remote sync status: no new execution-state changes since the last session.\n")
282→		return b.String()
283→	}
284→
285→	fmt.Fprintf(&b, "Remote sync status: pulled %d row%s across %d table%s.\n",
286→		report.RowsUpserted,
287→		pluralSuffix(report.RowsUpserted),
288→		report.TablesUpdated,
289→		pluralSuffix(report.TablesUpdated),
290→	)
291→
292→	if report.Delta == nil {
293→		return b.String()
294→	}
295→
296→	if report.Delta.TasksSent > 0 {
297→		fmt.Fprintf(&b, "Remote sends completed: %d.\n", report.Delta.TasksSent)
298→	}
299→	if report.Delta.TasksFailed > 0 {
300→		fmt.Fprintf(&b, "Remote send failures: %d. Check `nurge tasks list` and `nurge sends list` before advancing sequences.\n", report.Delta.TasksFailed)
301→	}
302→	if report.Delta.RepliesNeedingAttention > 0 {
303→		fmt.Fprintf(&b, "Replies needing attention: %d. Check `nurge replies queue` early in the session.\n", report.Delta.RepliesNeedingAttention)
304→		for _, item := range report.Delta.RecentReplies {
305→			if strings.TrimSpace(item.Subject) != "" {
306→				fmt.Fprintf(&b, "- Reply: %s (%s) — %s\n", item.ContactEmail, item.Classification, item.Subject)
307→				continue
308→			}
309→			fmt.Fprintf(&b, "- Reply: %s (%s)\n", item.ContactEmail, item.Classification)
310→		}
311→	}
312→	if report.Delta.EnrollmentsStopped > 0 {
313→		fmt.Fprintf(&b, "Enrollments stopped remotely: %d.\n", report.Delta.EnrollmentsStopped)
314→	}
315→	if report.Delta.EnrollmentsCompleted > 0 {
316→		fmt.Fprintf(&b, "Enrollments completed remotely: %d.\n", report.Delta.EnrollmentsCompleted)
317→	}
318→	if report.Delta.SuppressionsAdded > 0 {
319→		fmt.Fprintf(&b, "Suppressions added remotely: %d.\n", report.Delta.SuppressionsAdded)
320→	}
321→	if len(report.Delta.AuthExpiredMailboxes) > 0 {
322→		fmt.Fprintf(&b, "Mailbox reconnect required: %s. Guide the user to reconnect before new sends.\n", strings.Join(report.Delta.AuthExpiredMailboxes, ", "))
323→	}
324→
325→	return b.String()
326→}
