381→func pluralSuffix(count int, forms ...string) string {
382→	if len(forms) == 2 {
383→		if count == 1 {
384→			return forms[0]
385→		}
386→		return forms[1]
387→	}
388→	if count == 1 {
389→		return ""
390→	}
391→	return "s"
392→}
