 12→// ScoreContact computes a TierScore for a contact given ICP configuration
 13→// and database-derived intent signals.
 14→func ScoreContact(contact ContactData, icp ICPConfig, hasReply bool, hasActiveSequence bool) TierScore {
 15→	var score TierScore
 16→
 17→	// --- ICP Fit (0-100) ---
 18→	score.ICPFit, score.Reasons = scoreICPFit(contact, icp)
 19→
 20→	// --- Buying Trigger (0-100) ---
 21→	score.BuyingTrigger = scoreBuyingTrigger(contact.Signals, &score.Reasons)
 22→
 23→	// --- Intent Signal (0-100) ---
 24→	score.IntentSignal = scoreIntentSignal(contact, hasReply, hasActiveSequence, &score.Reasons)
 25→
 26→	// --- Accessibility (0-100) ---
 27→	score.Accessibility = scoreAccessibility(contact, &score.Reasons)
 28→
 29→	// --- Total (weighted sum) ---
 30→	score.Total = score.ICPFit*weightICPFit +
 31→		score.BuyingTrigger*weightBuyingTrigger +
 32→		score.IntentSignal*weightIntentSignal +
 33→		score.Accessibility*weightAccessibility
 34→
 35→	// Round to 1 decimal
 36→	score.Total = float64(int(score.Total*10)) / 10
 37→
 38→	// --- Tier assignment ---
 39→	switch {
 40→	case score.Total >= 70:
 41→		score.Tier = 1
 42→	case score.Total >= 40:
 43→		score.Tier = 2
 44→	default:
 45→		score.Tier = 3
 46→	}
 47→
 48→	return score
 49→}
