 51→func scoreICPFit(contact ContactData, icp ICPConfig) (float64, []string) {
 52→	var fit float64
 53→	var reasons []string
 54→
 55→	// Industry match: +40 exact, +20 related
 56→	if contact.Industry != "" && len(icp.TargetIndustries) > 0 {
 57→		contactInd := strings.ToLower(contact.Industry)
 58→		matched := false
 59→		for _, ind := range icp.TargetIndustries {
 60→			if strings.ToLower(ind) == contactInd {
 61→				fit += 40
 62→				reasons = append(reasons, fmt.Sprintf("industry match: %s", contact.Industry))
 63→				matched = true
 64→				break
 65→			}
 66→		}
 67→		if !matched {
 68→			// Check for related industry (substring match as heuristic)
 69→			for _, ind := range icp.TargetIndustries {
 70→				if strings.Contains(contactInd, strings.ToLower(ind)) ||
 71→					strings.Contains(strings.ToLower(ind), contactInd) {
 72→					fit += 20
 73→					reasons = append(reasons, fmt.Sprintf("related industry: %s ~ %s", contact.Industry, ind))
 74→					break
 75→				}
 76→			}
 77→		}
 78→	}
 79→
 80→	// Company size in range: +30
 81→	if contact.CompanySize != "" && icp.CompanySizeRange != "" {
 82→		if sizeInRange(contact.CompanySize, icp.CompanySizeRange) {
 83→			fit += 30
 84→			reasons = append(reasons, fmt.Sprintf("company size %s in range %s", contact.CompanySize, icp.CompanySizeRange))
 85→		}
 86→	}
 87→
 88→	// Geography match: +15
 89→	if icp.Geography != "" && contact.Domain != "" {
 90→		// Simple heuristic: geography is stored in config, we check domain TLD or company info
 91→		// This is a basic check; enrichment would improve accuracy
 92→		if strings.EqualFold(icp.Geography, "global") {
 93→			fit += 15
 94→			reasons = append(reasons, "geography: global target")
 95→		}
 96→	}
 97→
 98→	// Funding stage match: +15
 99→	if contact.FundingStage != "" && icp.FundingStage != "" {
100→		if strings.EqualFold(contact.FundingStage, icp.FundingStage) {
101→			fit += 15
102→			reasons = append(reasons, fmt.Sprintf("funding stage match: %s", contact.FundingStage))
103→		}
104→	}
105→
106→	// Title match (bonus, uses target titles from ICP)
107→	if contact.Title != "" && len(icp.TargetTitles) > 0 {
108→		contactTitle := strings.ToLower(contact.Title)
109→		for _, t := range icp.TargetTitles {
110→			if strings.Contains(contactTitle, strings.ToLower(t)) {
111→				// Title match doesn't add to the 100-point scale directly
112→				// but we record it as a reason for context
113→				reasons = append(reasons, fmt.Sprintf("title match: %s", contact.Title))
114→				break
115→			}
116→		}
117→	}
118→
119→	if fit > 100 {
120→		fit = 100
121→	}
122→	return fit, reasons
123→}
