125→func scoreBuyingTrigger(signals []string, reasons *[]string) float64 {
126→	triggerScores := map[string]float64{
127→		"funding":        40,
128→		"job_change":     35,
129→		"hiring":         25,
130→		"product_launch": 20,
131→		"expansion":      15,
132→	}
133→
134→	var total float64
135→	for _, sig := range signals {
136→		s := strings.ToLower(sig)
137→		if pts, ok := triggerScores[s]; ok {
138→			total += pts
139→			*reasons = append(*reasons, fmt.Sprintf("buying trigger: %s (+%.0f)", sig, pts))
140→		}
141→	}
142→
143→	if total > 100 {
144→		total = 100
145→	}
146→	return total
147→}
