149→func scoreIntentSignal(contact ContactData, hasReply bool, hasActiveSequence bool, reasons *[]string) float64 {
150→	var total float64
151→
152→	// Has prior email interaction (email_count > 0): +40
153→	if contact.EmailCount > 0 {
154→		total += 40
155→		*reasons = append(*reasons, fmt.Sprintf("prior emails: %d", contact.EmailCount))
156→	}
157→
158→	// Was previously replied to: +30
159→	if hasReply {
160→		total += 30
161→		*reasons = append(*reasons, "has reply event")
162→	}
163→
164→	// Has been emailed recently (last 30 days): +20
165→	if contact.LastEmailedAt != "" {
166→		if t, err := time.Parse(time.RFC3339, contact.LastEmailedAt); err == nil {
167→			if time.Since(t) <= 30*24*time.Hour {
168→				total += 20
169→				*reasons = append(*reasons, "emailed within last 30 days")
170→			}
171→		} else if t, err := time.Parse("2006-01-02T15:04:05", contact.LastEmailedAt); err == nil {
172→			if time.Since(t) <= 30*24*time.Hour {
173→				total += 20
174→				*reasons = append(*reasons, "emailed within last 30 days")
175→			}
176→		}
177→	}
178→
179→	// Part of active sequence: +10
180→	if hasActiveSequence {
181→		total += 10
182→		*reasons = append(*reasons, "active sequence enrollment")
183→	}
184→
185→	if total > 100 {
186→		total = 100
187→	}
188→	return total
189→}
190→
191→func scoreAccessibility(contact ContactData, reasons *[]string) float64 {
192→	var total float64
193→
194→	// Has verified email (we assume non-empty email is present — check for generic): +40
195→	if contact.Email != "" && !isGenericEmail(contact.Email) {
196→		total += 40
197→		*reasons = append(*reasons, "has direct email")
198→	} else if contact.Email != "" {
199→		total += 20
200→		*reasons = append(*reasons, "has email (generic)")
201→	}
202→
203→	// Has phone number: +20
204→	if contact.Phone != "" {
205→		total += 20
206→		*reasons = append(*reasons, "has phone number")
207→	}
208→
209→	// Has LinkedIn URL: +20
210→	if contact.LinkedInURL != "" {
211→		total += 20
212→		*reasons = append(*reasons, "has LinkedIn URL")
213→	}
214→
215→	// Has direct contact (not generic email): +20
216→	// Already handled above (40 for direct vs 20 for generic)
217→	// Use website as an additional signal
218→	if contact.Website != "" {
219→		total += 20
220→		*reasons = append(*reasons, "has website")
221→	}
222→
223→	if total > 100 {
224→		total = 100
225→	}
226→	return total
227→}
228→
229→// isGenericEmail checks if the email looks like a generic/role address.
230→func isGenericEmail(email string) bool {
231→	prefixes := []string{
232→		"info@", "contact@", "hello@", "support@", "sales@",
233→		"admin@", "help@", "team@", "office@", "general@",
234→		"enquiries@", "noreply@", "no-reply@",
235→	}
236→	lower := strings.ToLower(email)
237→	for _, p := range prefixes {
238→		if strings.HasPrefix(lower, p) {
239→			return true
240→		}
241→	}
242→	return false
243→}
244→
245→// sizeInRange checks if a company size string falls within a range like "50-500".
246→func sizeInRange(sizeStr, rangeStr string) bool {
247→	// Parse size: could be "150", "150-200", "~200", etc.
248→	size := parseFirstNumber(sizeStr)
249→	if size <= 0 {
250→		return false
251→	}
252→
253→	parts := strings.SplitN(rangeStr, "-", 2)
254→	if len(parts) != 2 {
255→		return false
256→	}
257→
258→	low := parseFirstNumber(parts[0])
259→	high := parseFirstNumber(parts[1])
260→	if low <= 0 || high <= 0 {
261→		return false
262→	}
263→
264→	return size >= low && size <= high
265→}
266→
267→// parseFirstNumber extracts the first integer from a string.
268→func parseFirstNumber(s string) int {
269→	s = strings.TrimSpace(s)
270→	// Strip non-digit prefix
271→	start := -1
272→	for i, c := range s {
273→		if c >= '0' && c <= '9' {
274→			if start == -1 {
275→				start = i
276→			}
277→		} else if start != -1 {
278→			n, err := strconv.Atoi(s[start:i])
279→			if err == nil {
280→				return n
281→			}
282→			return 0
283→		}
284→	}
285→	if start >= 0 {
286→		n, err := strconv.Atoi(s[start:])
287→		if err == nil {
288→			return n
289→		}
290→	}
291→	return 0
292→}
293→
294→// LoadICPConfig reads ICP configuration from the project config file.
295→func LoadICPConfig() ICPConfig {
296→	cfg, err := project.Load()
297→	if err != nil {
298→		return ICPConfig{}
299→	}
300→	return ICPConfigFromSettings(cfg.Settings)
301→}
302→
303→// ICPConfigFromSettings builds an ICPConfig from a settings map.
304→func ICPConfigFromSettings(settings map[string]string) ICPConfig {
305→	if settings == nil {
306→		return ICPConfig{}
307→	}
308→
309→	icp := ICPConfig{
310→		CompanySizeRange: settings["icp.company_size"],
311→		FundingStage:     settings["icp.stage"],
312→		Geography:        settings["icp.geography"],
313→	}
314→
315→	if ind := settings["icp.industry"]; ind != "" {
316→		icp.TargetIndustries = splitCSV(ind)
317→	}
318→	if titles := settings["icp.titles"]; titles != "" {
319→		icp.TargetTitles = splitCSV(titles)
320→	}
321→
322→	return icp
323→}
324→
325→func splitCSV(s string) []string {
326→	parts := strings.Split(s, ",")
327→	var out []string
328→	for _, p := range parts {
329→		p = strings.TrimSpace(p)
330→		if p != "" {
331→			out = append(out, p)
332→		}
333→	}
334→	return out
335→}
