134→// ListSkills returns a summary of all skills with their active version info.
135→func ListSkills(db *sql.DB) ([]SkillSummary, error) {
136→	rows, err := db.Query(`
137→		SELECT
138→			sv.skill_name,
139→			COALESCE(active.version, 0) AS active_version,
140→			COUNT(*) AS total_versions,
141→			MAX(sv.created_at) AS last_updated
142→		FROM skill_versions sv
143→		LEFT JOIN skill_versions active
144→			ON active.skill_name = sv.skill_name AND active.active = 1
145→		GROUP BY sv.skill_name
146→		ORDER BY sv.skill_name
147→	`)
148→	if err != nil {
149→		return nil, fmt.Errorf("listing skills: %w", err)
150→	}
151→	defer rows.Close()
152→
153→	var skills []SkillSummary
154→	for rows.Next() {
155→		var s SkillSummary
156→		if err := rows.Scan(&s.SkillName, &s.ActiveVersion, &s.TotalVersions, &s.LastUpdated); err != nil {
157→			return nil, fmt.Errorf("scanning skill: %w", err)
158→		}
159→		skills = append(skills, s)
160→	}
161→	return skills, rows.Err()
162→}
