187→// RollbackSkill restores a previous version of a skill by marking it as active
188→// and writing its content to disk.
189→func RollbackSkill(db *sql.DB, skillName string, version int) error {
190→	tx, err := db.Begin()
191→	if err != nil {
192→		return fmt.Errorf("beginning transaction: %w", err)
193→	}
194→	defer tx.Rollback()
195→
196→	// Verify the version exists
197→	var content string
198→	err = tx.QueryRow(
199→		`SELECT content FROM skill_versions WHERE skill_name = ? AND version = ?`,
200→		skillName, version,
201→	).Scan(&content)
202→	if err == sql.ErrNoRows {
203→		return fmt.Errorf("version %d not found for skill %s", version, skillName)
204→	}
205→	if err != nil {
206→		return fmt.Errorf("reading version: %w", err)
207→	}
208→
209→	// Deactivate all versions
210→	_, err = tx.Exec(
211→		`UPDATE skill_versions SET active = 0, updated_at = datetime('now') WHERE skill_name = ?`,
212→		skillName,
213→	)
214→	if err != nil {
215→		return fmt.Errorf("deactivating versions: %w", err)
216→	}
217→
218→	// Activate the target version
219→	_, err = tx.Exec(
220→		`UPDATE skill_versions SET active = 1, updated_at = datetime('now') WHERE skill_name = ? AND version = ?`,
221→		skillName, version,
222→	)
223→	if err != nil {
224→		return fmt.Errorf("activating version: %w", err)
225→	}
226→
227→	// Write file to disk BEFORE committing the transaction.
228→	// If the file write fails, the transaction rolls back automatically via defer.
229→	if err := writeSkillToDisk(skillName, content); err != nil {
230→		return err
231→	}
232→
233→	if err := tx.Commit(); err != nil {
234→		return fmt.Errorf("committing transaction: %w", err)
235→	}
236→
237→	return nil
238→}
