240→// PrintJSON marshals v to JSON and writes it to stdout.
241→func PrintJSON(v any) error {
242→	enc := json.NewEncoder(os.Stdout)
243→	enc.SetIndent("", "  ")
244→	return enc.Encode(v)
245→}
246→
247→// validateSkillName rejects skill names that could cause path traversal.
248→func validateSkillName(skillName string) error {
249→	if strings.Contains(skillName, "..") || strings.Contains(skillName, "/") || strings.Contains(skillName, "\\") {
250→		return fmt.Errorf("invalid skill name %q: must not contain '..', '/', or '\\'", skillName)
251→	}
252→	if skillName == "" {
253→		return fmt.Errorf("skill name must not be empty")
254→	}
255→	return nil
256→}
257→
258→func writeSkillToDisk(skillName, content string) error {
259→	if err := validateSkillName(skillName); err != nil {
260→		return err
261→	}
262→	skillDir := filepath.Join(".claude", "skills", skillName)
263→	// Double-check the resolved path stays within the skills directory
264→	absSkillDir, err := filepath.Abs(skillDir)
265→	if err != nil {
266→		return fmt.Errorf("resolving skill directory: %w", err)
267→	}
268→	absSkillsRoot, err := filepath.Abs(filepath.Join(".claude", "skills"))
269→	if err != nil {
270→		return fmt.Errorf("resolving skills root: %w", err)
271→	}
272→	if !strings.HasPrefix(absSkillDir, absSkillsRoot+string(filepath.Separator)) {
273→		return fmt.Errorf("skill path %q escapes skills directory", skillName)
274→	}
275→	if err := os.MkdirAll(skillDir, 0755); err != nil {
276→		return fmt.Errorf("creating skill directory: %w", err)
277→	}
278→	skillPath := filepath.Join(skillDir, "SKILL.md")
279→	if err := os.WriteFile(skillPath, []byte(content), 0644); err != nil {
280→		return fmt.Errorf("writing skill file: %w", err)
281→	}
282→	return nil
283→}
