 64→// runInit is the shared init logic used by both the root command and the hidden init alias.
 65→func runInit(cmd *cobra.Command, args []string) error {
 66→	dirCreated := ""
 67→
 68→	if len(args) == 1 {
 69→		dir := args[0]
 70→		if err := os.MkdirAll(dir, 0755); err != nil {
 71→			return fmt.Errorf("failed to create directory %s: %w", dir, err)
 72→		}
 73→		abs, err := filepath.Abs(dir)
 74→		if err != nil {
 75→			return err
