 78→			return fmt.Errorf("failed to enter directory %s: %w", dir, err)
 79→		}
 80→		dirCreated = dir
 81→	} else if !initForce {
 82→		// No directory arg: only init if current dir is empty or already initialized
 83→		empty, _ := project.IsDirEmpty(".")
 84→		alreadyInit := project.IsNurgeProject(".")
 85→		if !empty && !alreadyInit {
 86→			return cmd.Help()
 87→		}
