168→// isKnownCommand checks if name matches any registered subcommand.
169→func isKnownCommand(name string) bool {
170→	for _, c := range rootCmd.Commands() {
171→		if c.Name() == name {
172→			return true
173→		}
174→		for _, alias := range c.Aliases {
175→			if alias == name {
176→				return true
177→			}
178→		}
179→	}
180→	return name == "help" || name == "completion"
