183→func Execute() error {
184→	// Allow "nurge my-outbound" as shorthand for "nurge init my-outbound".
185→	// Cobra rejects unknown subcommands before RunE runs, so we rewrite args
186→	// when the first arg isn't a known subcommand or flag.
187→	if len(os.Args) > 1 {
188→		first := os.Args[1]
189→		if !strings.HasPrefix(first, "-") && !isKnownCommand(first) {
190→			os.Args = append([]string{os.Args[0], "init"}, os.Args[1:]...)
191→		}
192→	}
193→
194→	// Start async update check before stdout wrapping (uses stderr, no interaction).
195→	type updateResult struct {
196→		info *update.UpdateInfo
197→	}
198→	updateCh := make(chan updateResult, 1)
199→	cmdName := resolveCommandName()
200→	if cmdutil.BuildVersion != "dev" && cmdName != "update" && cmdName != "version" {
201→		go func() {
202→			ctx, cancel := context.WithTimeout(context.Background(), 2*time.Second)
203→			defer cancel()
204→			info, _ := update.CheckForUpdate(ctx, cmdutil.BuildVersion)
205→			updateCh <- updateResult{info: info}
206→		}()
207→	}
208→
209→	// Wrap stdout with a counting writer to measure output size.
210→	cw := metrics.NewCountingWriter(os.Stdout)
211→	rootCmd.SetOut(cw)
212→	origStdout := os.Stdout
213→	r, w, _ := os.Pipe()
214→	os.Stdout = w
215→
216→	// Copy pipe output to counting writer in background.
217→	done := make(chan struct{})
218→	go func() {
219→		buf := make([]byte, 4096)
220→		for {
221→			n, err := r.Read(buf)
222→			if n > 0 {
223→				cw.Write(buf[:n])
224→			}
225→			if err != nil {
226→				break
227→			}
228→		}
229→		close(done)
230→	}()
231→
232→	err := rootCmd.Execute()
233→
234→	// Restore stdout and flush.
235→	w.Close()
236→	<-done
237→	os.Stdout = origStdout
238→
239→	// Print update notification if available (to stderr, so --format json is clean).
240→	select {
241→	case r := <-updateCh:
242→		if r.info != nil {
243→			fmt.Fprintf(os.Stderr, "\n→ nurge %s available. Run: nurge update\n", r.info.LatestVersion)
244→		}
245→	default:
246→	}
247→
248→	// Log metrics if we're in a nurge project and this isn't the init/metrics command.
249→	if cmdName != "" && cmdName != "init" && cmdName != "metrics" && cmdName != "version" && db.Exists() {
250→		if d, dbErr := db.Open(); dbErr == nil {
251→			_ = metrics.EnsureTable(d)
252→			_ = metrics.Log(d, metrics.SessionID(), cmdName, cw.Count())
253→			d.Close()
254→		}
255→	}
256→
257→	return err
258→}
