260→// checkPendingSkillUpgrade prints a reminder if a pending skill upgrade marker exists.
261→func checkPendingSkillUpgrade() {
262→	markerPath := filepath.Join(".nurge", "pending-skill-upgrade.json")
263→	if _, err := os.Stat(markerPath); err == nil {
264→		fmt.Fprintf(os.Stderr, "→ Skill templates updated. Run /nurge:upgrade-skills in Claude Code to apply.\n")
265→	}
266→}
