268→// resolveCommandName returns the full command path (e.g. "emails list", "skills write").
269→func resolveCommandName() string {
270→	if len(os.Args) < 2 {
271→		return "init"
272→	}
273→	// Build command name from args, skipping flags.
274→	var parts []string
275→	for _, arg := range os.Args[1:] {
276→		if strings.HasPrefix(arg, "-") {
277→			break
278→		}
279→		parts = append(parts, arg)
280→	}
281→	if len(parts) == 0 {
282→		return "init"
283→	}
284→	return strings.Join(parts, " ")
285→}
