 14→var enrichSaveCmd = &cobra.Command{
 15→	Use:   "save",
 16→	Short: "Save enrichment results from stdin",
 17→	Long: `Reads enrichment JSON from stdin and updates contacts + enrichment cache.
 18→
 19→Accepts a single object or an array of objects:
 20→  {
 21→    "contact_email": "person@company.com",
 22→    "fields": { "name": "John Doe", "title": "CTO", "company": "Acme Inc" },
 23→    "source": "manual",
 24→    "provider": "clearbit"
 25→  }`,
 26→	RunE: func(cmd *cobra.Command, args []string) error {
 27→		stdin, _ := cmd.Flags().GetBool("stdin")
 28→		if !stdin {
 29→			return fmt.Errorf("--stdin flag is required")
 30→		}
 31→
 32→		data, err := io.ReadAll(os.Stdin)
 33→		if err != nil {
 34→			return fmt.Errorf("reading stdin: %w", err)
 35→		}
 36→
 37→		var inputs []enrichpkg.SaveInput
 38→		if err := json.Unmarshal(data, &inputs); err != nil {
 39→			var single enrichpkg.SaveInput
 40→			if err2 := json.Unmarshal(data, &single); err2 != nil {
 41→				return fmt.Errorf("parsing stdin JSON: %w", err)
 42→			}
 43→			inputs = []enrichpkg.SaveInput{single}
 44→		}
 45→
 46→		if len(inputs) == 0 {
 47→			return fmt.Errorf("no enrichment data provided")
 48→		}
 49→
 50→		d, err := db.Open()
 51→		if err != nil {
 52→			return err
 53→		}
 54→		defer d.Close()
 55→
 56→		results := enrichpkg.SaveBatch(d, inputs)
 57→
 58→		if enrichFormat == "json" {
 59→			enc := json.NewEncoder(os.Stdout)
 60→			enc.SetIndent("", "  ")
 61→			return enc.Encode(results)
 62→		}
 63→
 64→		var updated, cached, errCount int
 65→		for _, r := range results {
 66→			if r.Error != "" {
 67→				errCount++
 68→				fmt.Fprintf(os.Stderr, "  error: %s: %s\n", r.ContactEmail, r.Error)
 69→				continue
 70→			}
 71→			if r.ContactUpdated {
 72→				updated++
 73→			}
 74→			if r.CacheStored {
 75→				cached++
 76→			}
 77→		}
 78→
 79→		fmt.Printf("  Processed %d enrichment(s): %d contact(s) updated, %d cached", len(results), updated, cached)
 80→		if errCount > 0 {
 81→			fmt.Printf(", %d error(s)", errCount)
 82→		}
 83→		fmt.Println()
 84→		return nil
 85→	},
 86→}
