298→func readSkillContent(path string) (string, error) {
299→	var data []byte
300→	var err error
301→	if strings.TrimSpace(path) != "" {
302→		data, err = os.ReadFile(path)
303→		if err != nil {
304→			return "", fmt.Errorf("reading skill content: %w", err)
305→		}
306→	} else {
307→		data, err = io.ReadAll(os.Stdin)
308→		if err != nil {
309→			return "", fmt.Errorf("reading stdin: %w", err)
310→		}
311→	}
312→
313→	content := strings.TrimSpace(string(data))
314→	if content == "" {
315→		return "", fmt.Errorf("no skill content provided")
316→	}
317→	return content, nil
318→}
