46→	fmt.Printf("  New outreach: %d/%d sent | %d ready | %d active\n",
47→		ps.NewOutreach.SentToday, ps.NewOutreach.DailyLimit,
48→		ps.NewOutreach.Ready, ps.NewOutreach.Active)
49→	fmt.Printf("  Follow-ups:  %d sent today | %d due",
