 38→func acquireConnectLock(id string) (func(), error) {
 39→	lockDir := fmt.Sprintf(".nurge/connectors/%s", id)
 40→	if err := os.MkdirAll(lockDir, 0700); err != nil {
 41→		return nil, err
 42→	}
 43→	lockPath := filepath.Join(lockDir, ".connecting")
 44→	f, err := os.OpenFile(lockPath, os.O_CREATE|os.O_EXCL|os.O_WRONLY, 0600)
 45→	if err != nil {
 46→		if os.IsExist(err) {
 47→			return nil, fmt.Errorf("%s connection already in progress (remove %s if stale)", id, lockPath)
 48→		}
 49→		return nil, err
 50→	}
 51→	fmt.Fprintf(f, "%d", os.Getpid())
 52→	f.Close()
 53→	return func() { os.Remove(lockPath) }, nil
 54→}
