111→func connectGmail() error {
112→	af, err := account.LoadAuth()
113→	if err != nil || af.Token == "" {
114→		return fmt.Errorf("not logged in. Run: nurge account login")
115→	}
116→
117→	client := account.NewConvexClient(cmdutil.GetConvexURL())
118→
119→	fmt.Fprintf(os.Stderr, "  Requesting Gmail connection...\n")
120→	resp, err := client.ConnectGmail(af.Token)
121→	if err != nil {
122→		return fmt.Errorf("connect failed: %w", err)
123→	}
124→
125→	if resp.AlreadyConnected {
126→		if resp.MaxReached {
127→			fmt.Fprintf(os.Stderr, "  \033[32m✓\033[0m Max 2 Gmail accounts connected (%s)\n", resp.Email)
128→		} else {
129→			fmt.Fprintf(os.Stderr, "  \033[32m✓\033[0m Gmail already connected (%s)\n", resp.Email)
130→		}
131→		if project.IsNurgeProject(".") {
132→			_ = project.SetConnector("gmail", "email", resp.Email)
133→		}
134→		return nil
135→	}
136→
137→	fmt.Fprintf(os.Stderr, "  Opening browser to connect Gmail...\n")
138→	if err := util.OpenBrowser(resp.URL); err != nil {
139→		fmt.Fprintf(os.Stderr, "  Could not open browser. Please visit:\n  %s\n", resp.URL)
140→	}
141→
142→	fmt.Fprintf(os.Stderr, "  Waiting for Gmail connection...")
143→	timeout := time.After(5 * time.Minute)
144→	ticker := time.NewTicker(2 * time.Second)
145→	defer ticker.Stop()
146→
147→	for {
148→		select {
149→		case <-timeout:
150→			fmt.Fprintf(os.Stderr, "\n")
151→			return fmt.Errorf("timed out after 5 minutes waiting for Gmail connection.\n  Run `nurge connect gmail` to try again")
152→		case <-ticker.C:
153→			status, err := client.ConnectionStatus(af.Token, "GOOGLE")
154→			if err != nil {
155→				continue
156→			}
157→			if status.Connected {
158→				fmt.Fprintf(os.Stderr, "\n  \033[32m✓\033[0m Gmail connected (%s)\n", status.Email)
159→				if project.IsNurgeProject(".") {
160→					_ = project.SetConnector("gmail", "email", status.Email)
161→				}
162→				return nil
163→			}
164→			fmt.Fprintf(os.Stderr, ".")
165→		}
166→	}
167→}
