143→func gatherStatus() *sessionStatus {
144→	s := &sessionStatus{
145→		settings: make(map[string]string),
146→	}
147→
148→	// Load config (graceful — may not exist)
149→	cfg, err := project.Load()
150→	if err == nil {
151→		s.configLoaded = true
152→		s.setupCompleted = cfg.SetupCompleted
153→		s.connectors = cfg.Connectors
154→		if cfg.Settings != nil {
155→			s.settings = cfg.Settings
156→		}
157→	}
158→
159→	// Load DB stats (graceful — may not exist)
160→	if !db.Exists() {
161→		return s
162→	}
163→	d, err := db.Open()
164→	if err != nil {
165→		return s
166→	}
167→	defer d.Close()
168→
169→	stats, err := email.Stats(d)
170→	if err == nil {
171→		s.emailTotal = stats.Total
172→		s.outboundTotal = stats.ByClass["outbound"]
173→	}
174→
175→	weekly, err := email.ThisWeek(d)
176→	if err == nil {
177→		s.weeklyStats = weekly
178→	}
179→
180→	skills, err := session.ListSkills(d)
181→	if err == nil {
182→		s.skillCount = len(skills)
183→		for _, sk := range skills {
184→			s.skillNames = append(s.skillNames, sk.SkillName)
185→		}
186→	}
187→
188→	// Contact count (graceful)
189→	d.QueryRow("SELECT COUNT(*) FROM contacts").Scan(&s.contactCount)
190→
191→	// Learning count (graceful)
192→	d.QueryRow("SELECT COUNT(*) FROM learnings").Scan(&s.learningCount)
193→
194→	memories, err := session.ListStrategicMemory(d, 3)
195→	if err == nil {
196→		s.recentStrategicMemory = memories
197→	}
198→
199→	staleSkills, err := session.ListStaleSkills(d, 5)
200→	if err == nil {
201→		s.staleSkills = staleSkills
202→	}
203→
204→	// Pipeline status (graceful)
205→	if ps, err := pipeline.Status(d, time.Now()); err == nil {
206→		s.pipelineStatus = ps
207→	}
208→
209→	return s
210→}
