 17→func ListTemplates(d *sql.DB) ([]TemplateRecord, error) {
 18→	records := make([]TemplateRecord, 0, len(builtInTemplates))
 19→	seen := map[string]bool{}
 20→
 21→	for _, template := range BuiltInTemplates() {
 22→		records = append(records, TemplateRecord{
 23→			Template: template,
 24→			Source:   "built_in",
 25→		})
 26→		seen[strings.ToLower(template.Name)] = true
 27→	}
 28→
 29→	if d == nil {
 30→		return records, nil
 31→	}
 32→
 33→	rows, err := d.Query(`
 34→		SELECT name, description, steps_json, source
 35→		FROM sequence_templates
 36→		ORDER BY name ASC`)
 37→	if err != nil {
 38→		return nil, err
 39→	}
 40→	defer rows.Close()
 41→
 42→	for rows.Next() {
 43→		var (
 44→			name        string
 45→			description string
 46→			stepsJSON   string
 47→			source      string
 48→		)
 49→		if err := rows.Scan(&name, &description, &stepsJSON, &source); err != nil {
 50→			return nil, err
 51→		}
 52→		if seen[strings.ToLower(name)] {
 53→			continue
 54→		}
 55→		template, err := decodeTemplateSteps(name, stepsJSON)
 56→		if err != nil {
 57→			return nil, err
 58→		}
 59→		records = append(records, TemplateRecord{
 60→			Template:    template,
 61→			Description: description,
 62→			Source:      source,
 63→		})
 64→	}
 65→	if err := rows.Err(); err != nil {
 66→		return nil, err
 67→	}
 68→
 69→	sort.SliceStable(records, func(i, j int) bool {
 70→		return records[i].Name < records[j].Name
 71→	})
 72→	return records, nil
 73→}
