 97→func SaveTemplate(d *sql.DB, template Template, description string) (*TemplateRecord, error) {
 98→	if d == nil {
 99→		return nil, fmt.Errorf("database is required")
100→	}
101→	template.Name = strings.TrimSpace(template.Name)
102→	if template.Name == "" {
103→		return nil, fmt.Errorf("template name is required")
104→	}
105→	if _, exists := builtInTemplates[template.Name]; exists {
106→		return nil, fmt.Errorf("template %q is reserved by a built-in template", template.Name)
107→	}
108→	if len(template.Steps) == 0 {
109→		return nil, fmt.Errorf("template %q must have at least one step", template.Name)
110→	}
111→	for i := range template.Steps {
112→		if template.Steps[i].StepNumber <= 0 {
113→			template.Steps[i].StepNumber = i + 1
114→		}
115→		if strings.TrimSpace(template.Steps[i].Name) == "" {
116→			return nil, fmt.Errorf("template %q step %d is missing a name", template.Name, i+1)
117→		}
118→		if strings.TrimSpace(template.Steps[i].SendType) == "" {
119→			return nil, fmt.Errorf("template %q step %d is missing a send type", template.Name, i+1)
120→		}
121→		if _, err := stepDelay(template.Steps[i]); err != nil {
122→			return nil, err
123→		}
124→	}
125→
126→	stepsJSON, err := json.Marshal(template.Steps)
127→	if err != nil {
128→		return nil, err
129→	}
130→
131→	_, err = d.Exec(`
132→		INSERT INTO sequence_templates (id, name, description, steps_json, source)
133→		VALUES (?, ?, ?, ?, 'custom')
134→		ON CONFLICT(name) DO UPDATE SET
135→			description = excluded.description,
136→			steps_json = excluded.steps_json,
137→			source = excluded.source,
138→			updated_at = datetime('now')`,
139→		newID("tpl"), template.Name, description, string(stepsJSON),
140→	)
141→	if err != nil {
142→		return nil, err
143→	}
144→
145→	return &TemplateRecord{
146→		Template:    template,
147→		Description: description,
148→		Source:      "custom",
149→	}, nil
150→}
