152→func DeleteTemplate(d *sql.DB, name string) error {
153→	if d == nil {
154→		return fmt.Errorf("database is required")
155→	}
156→	name = strings.TrimSpace(name)
157→	if name == "" {
158→		return fmt.Errorf("template name is required")
159→	}
160→	if _, exists := builtInTemplates[name]; exists {
161→		return fmt.Errorf("cannot delete built-in template %q", name)
162→	}
163→	result, err := d.Exec(`DELETE FROM sequence_templates WHERE lower(name) = lower(?)`, name)
164→	if err != nil {
165→		return err
166→	}
167→	if rows, _ := result.RowsAffected(); rows == 0 {
168→		return fmt.Errorf("template %q not found", name)
169→	}
170→	return nil
171→}
