173→func decodeTemplateSteps(name, stepsJSON string) (Template, error) {
174→	var steps []TemplateStep
175→	if err := json.Unmarshal([]byte(stepsJSON), &steps); err != nil {
176→		return Template{}, fmt.Errorf("decoding template %q: %w", name, err)
177→	}
178→	return Template{Name: name, Steps: steps}, nil
179→}
