214→	os.Stdout = w
215→
216→	// Copy pipe output to counting writer in background.
217→	done := make(chan struct{})
218→	go func() {
219→		buf := make([]byte, 4096)
220→		for {
221→			n, err := r.Read(buf)
222→			if n > 0 {
223→				cw.Write(buf[:n])
224→			}
225→			if err != nil {
226→				break
227→			}
228→		}
229→		close(done)
230→	}()
231→
232→	err := rootCmd.Execute()
