	"github.com/usenurge/nurgesh/cmd/skill"
	"github.com/usenurge/nurgesh/internal/account"
	"github.com/usenurge/nurgesh/internal/db"
	"github.com/usenurge/nurgesh/internal/metrics"
	"github.com/usenurge/nurgesh/internal/project"
	"github.com/usenurge/nurgesh/internal/update"
)

// SetVersion sets the build version info from ldflags.
func SetVersion(version, commit, date string) {
	cmdutil.BuildVersion = version
	cmdutil.BuildCommit = commit
	cmdutil.BuildDate = date
}

// SetConvexURL sets the Convex deployment URL from ldflags.
func SetConvexURL(url string) {
	cmdutil.ConvexSiteURL = url
}

var (
	initForce     bool
	initSkipHooks bool
	initVerbose   bool
)

var rootCmd = &cobra.Command{
	Use:   "nurge [directory]",
	Short: "nurge — outbound that learns",
	Long:  "Nurge is an outbound sales tool that learns from your sent email history.\n\nRun 'nurge <directory>' to create a new project, or 'nurge' in an empty directory to initialize it.",
	RunE:  runInit,
}

var versionCmd = &cobra.Command{
	Use:         "version",
	Short:       "Print the version of nurge",
	Annotations: map[string]string{"skipAuth": "true"},
	Run: func(cmd *cobra.Command, args []string) {
		fmt.Printf("nurge %s (commit: %s, built: %s)\n", cmdutil.BuildVersion, cmdutil.BuildCommit, cmdutil.BuildDate)
	},
}

// runInit is the shared init logic used by both the root command and the hidden init alias.
func runInit(cmd *cobra.Command, args []string) error {
	dirCreated := ""

	if len(args) == 1 {
		dir := args[0]
		if err := os.MkdirAll(dir, 0755); err != nil {
			return fmt.Errorf("failed to create directory %s: %w", dir, err)
		}
		abs, err := filepath.Abs(dir)
		if err != nil {
			return err
		}
		if err := os.Chdir(abs); err != nil {
			return fmt.Errorf("failed to enter directory %s: %w", dir, err)
		}
		dirCreated = dir
	} else if !initForce {
		// No directory arg: only init if current dir is empty or already initialized
		empty, _ := project.IsDirEmpty(".")
		alreadyInit := project.IsNurgeProject(".")
		if !empty && !alreadyInit {
			return cmd.Help()
		}
	}

	// Check if current directory is non-empty (unless --force)
	if !initForce {
		empty, err := project.IsDirEmpty(".")
		if err != nil {
			return err
		}
		if !empty && !project.IsNurgeProject(".") {
			return fmt.Errorf("this directory isn't empty. Run: nurge <folder-name>")
		}
	}

	opts := project.Options{
		SkipHooks: initSkipHooks,
		Force:     initForce,
		Verbose:   initVerbose,
	}
	if err := project.Run(opts); err != nil {
		return err
	}

	if dirCreated != "" {
		fmt.Println()
		fmt.Printf("  Now run: cd %s\n", dirCreated)
		fmt.Println()
	}

	return nil
}

// shouldSkipAuth walks the command tree to check if any command in the
// chain has the skipAuth annotation. This handles cases like
// "nurge account login" where account has skipAuth.
func shouldSkipAuth(cmd *cobra.Command) bool {
	for c := cmd; c != nil; c = c.Parent() {
		if c.Annotations != nil && c.Annotations["skipAuth"] == "true" {
			return true
		}
	}
	return false
}

func init() {
	rootCmd.AddCommand(versionCmd)

	// Register subpackage commands.
	cloud.RegisterAll(rootCmd)
	seq.RegisterAll(rootCmd)
	email.RegisterAll(rootCmd)
	hook.RegisterAll(rootCmd)
	enrich.RegisterAll(rootCmd)
	conn.RegisterAll(rootCmd)
	ctx.RegisterAll(rootCmd)
	data.RegisterAll(rootCmd)
	pipeline.RegisterAll(rootCmd)
	skill.RegisterAll(rootCmd)

	rootCmd.Flags().BoolVar(&initForce, "force", false, "Re-run all steps even if already completed")
	rootCmd.Flags().BoolVar(&initSkipHooks, "skip-hooks", false, "Skip Claude Code hook installation")
	rootCmd.Flags().BoolVar(&initVerbose, "verbose", false, "Show detailed output")

	rootCmd.PersistentPreRunE = func(cmd *cobra.Command, args []string) error {
		// Root command (init) skips auth — it's the first thing a user runs
		if cmd == rootCmd ||
			shouldSkipAuth(cmd) ||
			cmd.Name() == "help" ||
			cmd.Name() == "completion" {
			return nil
		}
		if _, err := account.EnsureAuth(cmdutil.GetConvexURL(), cmdutil.GetDashboardURL()); err != nil {
			return err
		}

		// Check for pending skill upgrade marker.
		checkPendingSkillUpgrade()
		return nil
	}
}

// isKnownCommand checks if name matches any registered subcommand.
func isKnownCommand(name string) bool {
	for _, c := range rootCmd.Commands() {
		if c.Name() == name {
			return true
		}
		for _, alias := range c.Aliases {
			if alias == name {
				return true
			}
		}
	}
	return name == "help" || name == "completion"
}

func Execute() error {
	// Allow "nurge my-outbound" as shorthand for "nurge init my-outbound".
	// Cobra rejects unknown subcommands before RunE runs, so we rewrite args
	// when the first arg isn't a known subcommand or flag.
	if len(os.Args) > 1 {
		first := os.Args[1]
		if !strings.HasPrefix(first, "-") && !isKnownCommand(first) {
			os.Args = append([]string{os.Args[0], "init"}, os.Args[1:]...)
		}
	}

	// Start async update check before stdout wrapping (uses stderr, no interaction).
	type updateResult struct {
		info *update.UpdateInfo
	}
	updateCh := make(chan updateResult, 1)
	cmdName := resolveCommandName()
	if cmdutil.BuildVersion != "dev" && cmdName != "update" && cmdName != "version" {
		go func() {
			ctx, cancel := context.WithTimeout(context.Background(), 2*time.Second)
			defer cancel()
			info, _ := update.CheckForUpdate(ctx, cmdutil.BuildVersion)
			updateCh <- updateResult{info: info}
		}()
	}

	// Wrap stdout with a counting writer to measure output size.
	cw := metrics.NewCountingWriter(os.Stdout)
	rootCmd.SetOut(cw)
	origStdout := os.Stdout
	r, w, _ := os.Pipe()
	os.Stdout = w

	// Copy pipe output to counting writer in background.
	done := make(chan struct{})
	go func() {
		buf := make([]byte, 4096)
		for {
			n, err := r.Read(buf)
			if n > 0 {
				cw.Write(buf[:n])
			}
			if err != nil {
				break
			}
		}
		close(done)
	}()

	err := rootCmd.Execute()

	// Restore stdout and flush.
	w.Close()
	<-done
	os.Stdout = origStdout

	// Print update notification if available (to stderr, so --format json is clean).
	select {
	case r := <-updateCh:
		if r.info != nil {
			fmt.Fprintf(os.Stderr, "\n→ nurge %s available. Run: nurge update\n", r.info.LatestVersion)
		}
	default:
	}

	// Log metrics if we're in a nurge project and this isn't the init/metrics command.
	if cmdName != "" && cmdName != "init" && cmdName != "metrics" && cmdName != "version" && db.Exists() {
		if d, dbErr := db.Open(); dbErr == nil {
			_ = metrics.EnsureTable(d)
			_ = metrics.Log(d, metrics.SessionID(), cmdName, cw.Count())
			d.Close()
		}
	}

	return err
}

// checkPendingSkillUpgrade prints a reminder if a pending skill upgrade marker exists.
func checkPendingSkillUpgrade() {
	markerPath := filepath.Join(".nurge", "pending-skill-upgrade.json")
	if _, err := os.Stat(markerPath); err == nil {
		fmt.Fprintf(os.Stderr, "→ Skill templates updated. Run /nurge:upgrade-skills in Claude Code to apply.\n")
	}
}

// resolveCommandName returns the full command path (e.g. "emails list", "skills write").
func resolveCommandName() string {
	if len(os.Args) < 2 {
		return "init"
	}
	// Build command name from args, skipping flags.
	var parts []string
	for _, arg := range os.Args[1:] {
		if strings.HasPrefix(arg, "-") {
			break
		}
		parts = append(parts, arg)
	}
	if len(parts) == 0 {
		return "init"
	}
	return strings.Join(parts, " ")
}

package assembly

import (
	"database/sql"
	"encoding/json"
	"fmt"
)

// ResearchDossier is a per-prospect intelligence brief used during context assembly.
type ResearchDossier struct {
	ID            int             `json:"id"`
	ContactEmail  string          `json:"contact_email"`
	ContactName   string          `json:"contact_name,omitempty"`
	CompanyDomain string          `json:"company_domain,omitempty"`
	Dossier       json.RawMessage `json:"dossier"`
	Tier          int             `json:"tier"`
	ResearchDepth string          `json:"research_depth,omitempty"`
	CreatedAt     string          `json:"created_at"`
	UpdatedAt     string          `json:"updated_at"`
}

// SaveDossier inserts or updates a research dossier for a prospect.
func SaveDossier(db *sql.DB, contactEmail, contactName, companyDomain string, dossier json.RawMessage, tier int, depth string) error {
	if contactEmail == "" {
		return fmt.Errorf("contact email is required")
	}
	if !json.Valid(dossier) {
		return fmt.Errorf("dossier must be valid JSON")
	}

	_, err := db.Exec(`
		INSERT INTO research_dossiers (contact_email, contact_name, company_domain, dossier, tier, research_depth)
		VALUES (?, ?, ?, ?, ?, ?)
		ON CONFLICT(contact_email) DO UPDATE SET
			contact_name = COALESCE(NULLIF(excluded.contact_name, ''), research_dossiers.contact_name),
			company_domain = COALESCE(NULLIF(excluded.company_domain, ''), research_dossiers.company_domain),
			dossier = excluded.dossier,
			tier = excluded.tier,
			research_depth = excluded.research_depth,
			updated_at = datetime('now')
	`, contactEmail, contactName, companyDomain, string(dossier), tier, depth)
	if err != nil {
		return fmt.Errorf("saving dossier: %w", err)
	}
	return nil
}

// GetDossier retrieves the research dossier for a prospect by email.
func GetDossier(db *sql.DB, contactEmail string) (*ResearchDossier, error) {
	var d ResearchDossier
	var dossierStr string
	err := db.QueryRow(`
		SELECT id, contact_email, contact_name, company_domain, dossier, tier, research_depth, created_at, updated_at
		FROM research_dossiers WHERE contact_email = ?
	`, contactEmail).Scan(&d.ID, &d.ContactEmail, &d.ContactName, &d.CompanyDomain, &dossierStr, &d.Tier, &d.ResearchDepth, &d.CreatedAt, &d.UpdatedAt)
	if err == sql.ErrNoRows {
		return nil, nil
	}
	if err != nil {
		return nil, fmt.Errorf("getting dossier: %w", err)
	}
	d.Dossier = json.RawMessage(dossierStr)
	return &d, nil
}

// ListDossiers returns all dossiers, optionally filtered by company domain.
func ListDossiers(db *sql.DB, domain string, limit int) ([]ResearchDossier, error) {
	query := `SELECT id, contact_email, contact_name, company_domain, dossier, tier, research_depth, created_at, updated_at
		FROM research_dossiers`
	var args []any
	if domain != "" {
		query += ` WHERE company_domain = ?`
		args = append(args, domain)
	}
	query += ` ORDER BY updated_at DESC`
	if limit > 0 {
		query += ` LIMIT ?`
		args = append(args, limit)
	}

	rows, err := db.Query(query, args...)
	if err != nil {
		return nil, fmt.Errorf("listing dossiers: %w", err)
	}
	defer rows.Close()

	var dossiers []ResearchDossier
	for rows.Next() {
		var d ResearchDossier
		var dossierStr string
		if err := rows.Scan(&d.ID, &d.ContactEmail, &d.ContactName, &d.CompanyDomain, &dossierStr, &d.Tier, &d.ResearchDepth, &d.CreatedAt, &d.UpdatedAt); err != nil {
			return nil, fmt.Errorf("scanning dossier: %w", err)
		}
		d.Dossier = json.RawMessage(dossierStr)
		dossiers = append(dossiers, d)
	}
	return dossiers, rows.Err()
}

// DeleteDossier removes a research dossier by contact email.
func DeleteDossier(db *sql.DB, contactEmail string) error {
	_, err := db.Exec(`DELETE FROM research_dossiers WHERE contact_email = ?`, contactEmail)
	return err
}

