package ctx

import (
	"encoding/json"
	"fmt"
	"io"
	"os"

	"github.com/spf13/cobra"
	"github.com/usenurge/nurgesh/internal/assembly"
	"github.com/usenurge/nurgesh/internal/db"
)

var knowledgeFormat string

var knowledgeCmd = &cobra.Command{
	Use:   "knowledge",
	Short: "Manage knowledge atoms for context assembly",
}

var knowledgeSeedCmd = &cobra.Command{
	Use:   "seed",
	Short: "Seed a knowledge atom from stdin",
	Long:  "Reads JSON content from stdin and stores it as a knowledge atom.",
	RunE: func(cmd *cobra.Command, args []string) error {
		atomType, _ := cmd.Flags().GetString("atom")
		scope, _ := cmd.Flags().GetString("scope")
		source, _ := cmd.Flags().GetString("source")

		if atomType == "" {
			return fmt.Errorf("--atom is required (tone, hooks, positioning, personas, objections, signals, compliance)")
		}

		data, err := io.ReadAll(os.Stdin)
		if err != nil {
			return fmt.Errorf("reading stdin: %w", err)
		}
		if len(data) == 0 {
			return fmt.Errorf("no input provided on stdin")
		}
		if !json.Valid(data) {
			return fmt.Errorf("input must be valid JSON")
		}

		d, err := db.Open()
		if err != nil {
			return err
		}
		defer d.Close()

		id, err := assembly.SeedAtom(d, assembly.AtomType(atomType), scope, json.RawMessage(data), source)
		if err != nil {
			return err
		}

		if knowledgeFormat == "json" {
			enc := json.NewEncoder(os.Stdout)
			enc.SetIndent("", "  ")
			return enc.Encode(map[string]any{"id": id, "atom_type": atomType, "scope": scope, "status": "seeded"})
		}
		fmt.Printf("Seeded %s atom (scope: %q, id: %d)\n", atomType, scope, id)
		return nil
	},
}

var knowledgeListCmd = &cobra.Command{
	Use:   "list",
	Short: "List all knowledge atoms",
	RunE: func(cmd *cobra.Command, args []string) error {
		filterType, _ := cmd.Flags().GetString("atom")

		d, err := db.Open()
		if err != nil {
			return err
		}
		defer d.Close()

		atoms, err := assembly.ListAtoms(d, filterType)
		if err != nil {
			return err
		}

		if knowledgeFormat == "json" {
			enc := json.NewEncoder(os.Stdout)
			enc.SetIndent("", "  ")
			return enc.Encode(atoms)
		}

		if len(atoms) == 0 {
			fmt.Println("No knowledge atoms found.")
			return nil
		}

		for _, a := range atoms {
			scope := a.Scope
			if scope == "" {
				scope = "global"
			}
			fmt.Printf("  [%d] %s/%s (confidence: %.1f, uses: %d, source: %s)\n",
				a.ID, a.AtomType, scope, a.Confidence, a.UseCount, a.Source)
		}
		return nil
	},
}

var knowledgeQueryCmd = &cobra.Command{
	Use:   "query",
	Short: "Query knowledge atoms by type and scope",
	RunE: func(cmd *cobra.Command, args []string) error {
		atomType, _ := cmd.Flags().GetString("atom")
		scope, _ := cmd.Flags().GetString("scope")

		if atomType == "" {
			return fmt.Errorf("--atom is required")
		}

		d, err := db.Open()
		if err != nil {
			return err
		}
		defer d.Close()

		scopes := []string{}
		if scope != "" {
			scopes = append(scopes, scope)
		}

		atoms, err := assembly.QueryAtoms(d, assembly.AtomType(atomType), scopes...)
		if err != nil {
			return err
		}

		if knowledgeFormat == "json" {
			enc := json.NewEncoder(os.Stdout)
			enc.SetIndent("", "  ")
			return enc.Encode(atoms)
		}

		if len(atoms) == 0 {
			fmt.Printf("No %s atoms found.\n", atomType)
			return nil
		}

		for _, a := range atoms {
			scope := a.Scope
			if scope == "" {
				scope = "global"
			}
			fmt.Printf("  [%d] %s/%s:\n", a.ID, a.AtomType, scope)
			var pretty json.RawMessage
			if json.Unmarshal(a.Content, &pretty) == nil {
				indented, _ := json.MarshalIndent(pretty, "    ", "  ")
				fmt.Printf("    %s\n", indented)
			}
		}
		return nil
	},
}

func init() {
	knowledgeCmd.PersistentFlags().StringVar(&knowledgeFormat, "format", "", "Output format (json)")

	knowledgeSeedCmd.Flags().String("atom", "", "Atom type (tone, hooks, positioning, personas, objections, signals, compliance)")
	knowledgeSeedCmd.Flags().String("scope", "", "Scope (persona name, tier, geography, or empty for global)")
	knowledgeSeedCmd.Flags().String("source", "setup", "Source of this atom (setup, learning, user)")

	knowledgeListCmd.Flags().String("atom", "", "Filter by atom type")

	knowledgeQueryCmd.Flags().String("atom", "", "Atom type to query")
	knowledgeQueryCmd.Flags().String("scope", "", "Scope to query (falls back to global)")

	knowledgeCmd.AddCommand(knowledgeSeedCmd, knowledgeListCmd, knowledgeQueryCmd)
}

