package email

import (
	"database/sql"
	"strings"
	"time"

	gm "google.golang.org/api/gmail/v1"

	"github.com/usenurge/nurgesh/internal/sequence"
)

type ReplySyncResult struct {
	ThreadsScanned  int `json:"threads_scanned"`
	MessagesScanned int `json:"messages_scanned"`
	RepliesRecorded int `json:"replies_recorded"`
	Paused          int `json:"paused"`
	Stopped         int `json:"stopped"`
}

func SyncReplies(srv *gm.Service, d *sql.DB, mailboxEmail string, now time.Time) (*ReplySyncResult, error) {
	if now.IsZero() {
		now = time.Now()
	}

	enrollments, err := sequence.ListEnrollments(d, sequence.StatusActive, 0)
	if err != nil {
		return nil, err
	}

	result := &ReplySyncResult{}
	for _, enrollment := range enrollments {
		if enrollment.ThreadID == "" {
			continue
		}
		if mailboxEmail != "" && !strings.EqualFold(mailboxEmail, enrollment.MailboxEmail) {
			continue
		}

		thread, err := srv.Users.Threads.Get("me", enrollment.ThreadID).Format("metadata").
			MetadataHeaders("Subject", "From", "To", "Cc", "Date").Do()
		if err != nil {
			return nil, err
		}
		result.ThreadsScanned++

		watermark := latestKnownThreadTime(enrollment)
		for i := 0; i < len(thread.Messages); i++ {
			result.MessagesScanned++
			raw := parseMessage(thread.Messages[i])
			raw.Direction = inferDirection(raw, enrollment.MailboxEmail)
			if raw.Direction != "inbound" {
				continue
			}

			occurredAt, ok := parseStoredEmailTime(raw.Date)
			if !ok {
				continue
			}
			if !watermark.IsZero() && !occurredAt.After(watermark) {
				continue
			}

			raw.ThreadID = enrollment.ThreadID
			raw.Direction = "inbound"
			if err := StoreEmail(d, raw); err != nil {
				return nil, err
			}

			reply, err := sequence.RecordReply(d, sequence.ReplyOptions{
				EnrollmentID:   enrollment.ID,
				MailboxID:      enrollment.MailboxID,
				ThreadID:       enrollment.ThreadID,
				MessageID:      raw.ID,
				ContactEmail:   raw.FromEmail,
				Classification: classifyReply(raw.FromEmail, raw.Subject, raw.Snippet),
				Subject:        raw.Subject,
				Snippet:        raw.Snippet,
				OccurredAt:     occurredAt,
			})
			if err != nil {
				return nil, err
			}

			result.RepliesRecorded++
			if reply.Classification == "not_interested" || reply.Classification == "unsubscribe" || reply.Classification == "bounced" {
				result.Stopped++
			} else {
				result.Paused++
			}
		}
	}

	return result, nil
}

func classifyReply(fromEmail, subject, snippet string) string {
	text := strings.ToLower(strings.TrimSpace(fromEmail) + "\n" + subject + "\n" + snippet)
	switch {
	case containsAny(text, "mailer-daemon", "postmaster", "delivery status notification", "undeliverable", "message blocked", "delivery has failed"):
		return "bounced"
	case containsAny(text, "out of office", "out-of-office", "automatic reply", "auto-reply", "ooo", "away until"):
		return "out_of_office"
	case containsAny(text, "unsubscribe", "stop emailing", "do not contact"):
		return "unsubscribe"
	case containsAny(text, "not interested", "no interest", "no thanks", "remove me"):
		return "not_interested"
	case containsAny(text, "yes", "interested", "sounds good", "let's chat", "let us chat", "worth a look", "happy to talk"):
		return "interested"
	case containsAny(text, "reach out to", "talk to", "speak with", "contact ") && strings.Contains(text, "@"):
		return "referral"
	default:
		return "replied"
	}
}

func latestKnownThreadTime(enrollment sequence.Enrollment) time.Time {
	candidates := []string{enrollment.LastReplyAt, enrollment.LastSentAt}
	for _, candidate := range candidates {
		if candidate == "" {
			continue
		}
		if ts, err := time.Parse(time.RFC3339, candidate); err == nil {
			return ts.UTC()
		}
	}
	return time.Time{}
}

func inferDirection(message *RawMessage, mailboxEmail string) string {
	if mailboxEmail != "" && strings.EqualFold(strings.TrimSpace(message.FromEmail), strings.TrimSpace(mailboxEmail)) {
		return "outbound"
	}
	return "inbound"
}

func containsAny(text string, needles ...string) bool {
	for _, needle := range needles {
		if strings.Contains(text, needle) {
			return true
		}
	}
	return false
}

package db

import (
	"database/sql"
	"fmt"
)

// EnsureMigrations runs schema migrations (adding columns to existing tables).
// Exported so tests that create in-memory DBs can also apply migrations.
func EnsureMigrations(db *sql.DB) error {
	return ensureMigrations(db)
}

func ensureMigrations(db *sql.DB) error {
	tx, err := db.Begin()
	if err != nil {
		return fmt.Errorf("beginning migration transaction: %w", err)
	}
	defer tx.Rollback() // no-op after successful commit

	type columnSpec struct {
		table         string
		column        string
		columnTypeDDL string
	}

	columns := []columnSpec{
		{table: "emails", column: "direction", columnTypeDDL: "TEXT NOT NULL DEFAULT 'outbound'"},
		{table: "mailboxes", column: "min_gap_minutes", columnTypeDDL: "INTEGER NOT NULL DEFAULT 0"},
		{table: "mailboxes", column: "transport_email", columnTypeDDL: "TEXT NOT NULL DEFAULT ''"},
		{table: "mailboxes", column: "rotation_group", columnTypeDDL: "TEXT NOT NULL DEFAULT 'default'"},
		{table: "mailboxes", column: "warmup_started_at", columnTypeDDL: "TEXT DEFAULT ''"},
		{table: "mailboxes", column: "send_window_start_hour", columnTypeDDL: "INTEGER NOT NULL DEFAULT 8"},
		{table: "mailboxes", column: "send_window_end_hour", columnTypeDDL: "INTEGER NOT NULL DEFAULT 18"},
		{table: "mailboxes", column: "send_window_timezone", columnTypeDDL: "TEXT NOT NULL DEFAULT 'Local'"},
		{table: "mailboxes", column: "reputation_score", columnTypeDDL: "INTEGER NOT NULL DEFAULT 100"},
		{table: "mailboxes", column: "priority", columnTypeDDL: "INTEGER NOT NULL DEFAULT 0"},
		{table: "mailboxes", column: "last_used_at", columnTypeDDL: "TEXT DEFAULT ''"},
		{table: "mailboxes", column: "last_bounce_at", columnTypeDDL: "TEXT DEFAULT ''"},
		{table: "sequence_enrollments", column: "campaign_name", columnTypeDDL: "TEXT NOT NULL DEFAULT ''"},
		{table: "sequence_enrollments", column: "status_reason", columnTypeDDL: "TEXT DEFAULT ''"},
		{table: "sequence_enrollments", column: "reply_state", columnTypeDDL: "TEXT DEFAULT ''"},
		{table: "sequence_enrollments", column: "last_reply_at", columnTypeDDL: "TEXT DEFAULT ''"},
		{table: "sequence_enrollments", column: "initial_body", columnTypeDDL: "TEXT DEFAULT ''"},
		{table: "follow_up_tasks", column: "body", columnTypeDDL: "TEXT DEFAULT ''"},
		{table: "follow_up_tasks", column: "last_attempt_at", columnTypeDDL: "TEXT DEFAULT ''"},
		{table: "follow_up_tasks", column: "last_error", columnTypeDDL: "TEXT DEFAULT ''"},
		{table: "follow_up_tasks", column: "attempt_count", columnTypeDDL: "INTEGER NOT NULL DEFAULT 0"},

		// Unipile ID fields for threading and reply support
		{table: "emails", column: "unipile_id", columnTypeDDL: "TEXT DEFAULT ''"},
		{table: "emails", column: "provider_id", columnTypeDDL: "TEXT DEFAULT ''"},
		{table: "emails", column: "unipile_account_id", columnTypeDDL: "TEXT DEFAULT ''"},

		{table: "follow_up_tasks", column: "send_status", columnTypeDDL: "TEXT NOT NULL DEFAULT 'pending'"},
		{table: "follow_up_tasks", column: "unipile_message_id", columnTypeDDL: "TEXT DEFAULT ''"},
		{table: "follow_up_tasks", column: "provider_id", columnTypeDDL: "TEXT DEFAULT ''"},

		{table: "sequence_enrollments", column: "unipile_thread_provider_id", columnTypeDDL: "TEXT DEFAULT ''"},
		{table: "sequence_enrollments", column: "unipile_account_id", columnTypeDDL: "TEXT DEFAULT ''"},

		{table: "reply_events", column: "status", columnTypeDDL: "TEXT NOT NULL DEFAULT 'open'"},
		{table: "reply_events", column: "assigned_to", columnTypeDDL: "TEXT DEFAULT ''"},
		{table: "reply_events", column: "draft_reply", columnTypeDDL: "TEXT DEFAULT ''"},
		{table: "reply_events", column: "handled_at", columnTypeDDL: "TEXT DEFAULT ''"},

		// sync_version for all synced tables (monotonic version from Convex)
		{table: "emails", column: "sync_version", columnTypeDDL: "INTEGER DEFAULT 0"},
		{table: "contacts", column: "sync_version", columnTypeDDL: "INTEGER DEFAULT 0"},
		{table: "mailboxes", column: "sync_version", columnTypeDDL: "INTEGER DEFAULT 0"},
		{table: "sequence_enrollments", column: "sync_version", columnTypeDDL: "INTEGER DEFAULT 0"},
		{table: "follow_up_tasks", column: "sync_version", columnTypeDDL: "INTEGER DEFAULT 0"},
		{table: "suppressions", column: "sync_version", columnTypeDDL: "INTEGER DEFAULT 0"},
		{table: "reply_events", column: "sync_version", columnTypeDDL: "INTEGER DEFAULT 0"},
		{table: "learnings", column: "sync_version", columnTypeDDL: "INTEGER DEFAULT 0"},
		{table: "skill_versions", column: "sync_version", columnTypeDDL: "INTEGER DEFAULT 0"},
		{table: "deals", column: "sync_version", columnTypeDDL: "INTEGER DEFAULT 0"},

		// updated_at for local-state tables that sync uses for change detection
		{table: "learnings", column: "updated_at", columnTypeDDL: "TEXT DEFAULT (datetime('now'))"},
		{table: "skill_versions", column: "updated_at", columnTypeDDL: "TEXT DEFAULT (datetime('now'))"},
		{table: "deals", column: "updated_at", columnTypeDDL: "TEXT DEFAULT (datetime('now'))"},

		// Distillation tracking
		{table: "learnings", column: "distilled_at", columnTypeDDL: "TEXT DEFAULT ''"},

		// Context assembly: contact enrichment fields
		{table: "contacts", column: "tier", columnTypeDDL: "INTEGER DEFAULT 0"},
		{table: "contacts", column: "tier_score", columnTypeDDL: "REAL DEFAULT 0"},
		{table: "contacts", column: "tier_scored_at", columnTypeDDL: "TEXT DEFAULT ''"},
		{table: "contacts", column: "enriched_at", columnTypeDDL: "TEXT DEFAULT ''"},
		{table: "contacts", column: "enrichment_sources", columnTypeDDL: "TEXT DEFAULT '[]'"},
		{table: "contacts", column: "linkedin_url", columnTypeDDL: "TEXT DEFAULT ''"},
		{table: "contacts", column: "website", columnTypeDDL: "TEXT DEFAULT ''"},
		{table: "contacts", column: "funding_stage", columnTypeDDL: "TEXT DEFAULT ''"},
		{table: "contacts", column: "company_size", columnTypeDDL: "TEXT DEFAULT ''"},
		{table: "contacts", column: "industry", columnTypeDDL: "TEXT DEFAULT ''"},
		{table: "contacts", column: "tech_stack", columnTypeDDL: "TEXT DEFAULT '[]'"},
		{table: "contacts", column: "signals", columnTypeDDL: "TEXT DEFAULT '[]'"},
		{table: "contacts", column: "data_confidence", columnTypeDDL: "REAL DEFAULT 0"},
		{table: "contacts", column: "resolve_source", columnTypeDDL: "TEXT DEFAULT ''"},
		{table: "contacts", column: "past_companies", columnTypeDDL: "TEXT DEFAULT '[]'"},
	}

	for _, spec := range columns {
		ok, err := hasColumnTx(tx, spec.table, spec.column)
		if err != nil {
			return err
		}
		if ok {
			continue
		}
		if _, err := tx.Exec(fmt.Sprintf("ALTER TABLE %s ADD COLUMN %s %s", spec.table, spec.column, spec.columnTypeDDL)); err != nil {
			return fmt.Errorf("adding %s.%s: %w", spec.table, spec.column, err)
		}
	}

	// Backfill default values for newly added columns
	if _, err := tx.Exec(`UPDATE mailboxes SET warmup_started_at = created_at WHERE warmup_started_at = ''`); err != nil {
		return fmt.Errorf("backfilling mailboxes.warmup_started_at: %w", err)
	}
	if _, err := tx.Exec(`UPDATE learnings SET updated_at = COALESCE(NULLIF(updated_at, ''), created_at, datetime('now'))`); err != nil {
		return fmt.Errorf("backfilling learnings.updated_at: %w", err)
	}
	if _, err := tx.Exec(`UPDATE skill_versions SET updated_at = COALESCE(NULLIF(updated_at, ''), created_at, datetime('now'))`); err != nil {
		return fmt.Errorf("backfilling skill_versions.updated_at: %w", err)
	}
	if _, err := tx.Exec(`UPDATE deals SET updated_at = COALESCE(NULLIF(updated_at, ''), created_at, synced_at, datetime('now'))`); err != nil {
		return fmt.Errorf("backfilling deals.updated_at: %w", err)
	}

	// Recreate idx_knowledge_atoms_scope as UNIQUE for existing databases
	// that may have created it as a non-unique index.
	if _, err := tx.Exec(`DROP INDEX IF EXISTS idx_knowledge_atoms_scope`); err != nil {
		return fmt.Errorf("dropping non-unique idx_knowledge_atoms_scope: %w", err)
	}
	if _, err := tx.Exec(`CREATE UNIQUE INDEX IF NOT EXISTS idx_knowledge_atoms_scope ON knowledge_atoms(atom_type, scope)`); err != nil {
		return fmt.Errorf("recreating idx_knowledge_atoms_scope as unique: %w", err)
	}

	if err := tx.Commit(); err != nil {
		return fmt.Errorf("committing migration transaction: %w", err)
	}
	return nil
}

func hasColumnTx(tx *sql.Tx, table, column string) (bool, error) {
	rows, err := tx.Query(fmt.Sprintf("PRAGMA table_info(%s)", table))
	if err != nil {
		return false, err
	}
	defer rows.Close()

	for rows.Next() {
		var (
			cid      int
			name     string
			kind     string
			notNull  int
			defaultV sql.NullString
			pk       int
		)
		if err := rows.Scan(&cid, &name, &kind, &notNull, &defaultV, &pk); err != nil {
			return false, err
		}
		if name == column {
			return true, nil
		}
	}

	return false, rows.Err()
}

