package email

import (
	"encoding/json"
	"fmt"
	"os"
	"time"

	"github.com/spf13/cobra"
	"github.com/usenurge/nurgesh/cmd/cmdutil"
	"github.com/usenurge/nurgesh/internal/db"
	emailpkg "github.com/usenurge/nurgesh/internal/email"
	"github.com/usenurge/nurgesh/internal/project"
	"github.com/usenurge/nurgesh/internal/sequence"
)

var repliesFormat string
var repliesLimit int
var repliesAssignedTo string
var repliesDraftBody string

var repliesCmd = &cobra.Command{
	Use:   "replies",
	Short: "Sync and inspect inbound replies for active sequences",
}

var repliesSyncCmd = &cobra.Command{
	Use:   "sync",
	Short: "Sync inbound replies for active sequence threads",
	RunE: func(cmd *cobra.Command, args []string) error {
		cfg, err := project.Load()
		if err != nil {
			return fmt.Errorf("loading config: %w", err)
		}

		gmail, ok := cfg.Connectors["gmail"]
		if !ok || !gmail.Connected {
			return fmt.Errorf("Gmail not connected. Run: nurge connect gmail")
		}

		d, err := db.Open()
		if err != nil {
			return err
		}
		defer d.Close()

		srv, err := emailpkg.NewClient("")
		if err != nil {
			return fmt.Errorf("connecting to Gmail: %w", err)
		}

		result, err := emailpkg.SyncReplies(srv, d, gmail.Account, time.Now())
		if err != nil {
			return err
		}

		if repliesFormat == "json" {
			enc := json.NewEncoder(os.Stdout)
			enc.SetIndent("", "  ")
			return enc.Encode(result)
		}

		fmt.Printf("  ✓ Scanned %d threads (%d messages)\n", result.ThreadsScanned, result.MessagesScanned)
		fmt.Printf("    replies recorded: %d\n", result.RepliesRecorded)
		fmt.Printf("    paused: %d | stopped: %d\n", result.Paused, result.Stopped)
		return nil
	},
}

var repliesListCmd = &cobra.Command{
	Use:   "list",
	Short: "List recorded reply events",
	RunE: func(cmd *cobra.Command, args []string) error {
		d, err := db.Open()
		if err != nil {
			return err
		}
		defer d.Close()

		events, err := sequence.ListReplyEvents(d, repliesLimit)
		if err != nil {
			return err
		}

		if repliesFormat == "json" {
			enc := json.NewEncoder(os.Stdout)
			enc.SetIndent("", "  ")
			return enc.Encode(events)
		}

		if len(events) == 0 {
			fmt.Println("  No replies recorded yet.")
			return nil
		}

		for _, event := range events {
			state := event.Classification
			if event.Status != "" {
				state += " / " + event.Status
			}
			fmt.Printf("  [%s] %s\n", state, event.ContactEmail)
			fmt.Printf("    thread: %s | message: %s\n", event.ThreadID, event.MessageID)
			if event.Subject != "" {
				fmt.Printf("    subject: %s\n", event.Subject)
			}
			if event.Snippet != "" {
				fmt.Printf("    snippet: %s\n", event.Snippet)
			}
			if event.DraftReply != "" {
				fmt.Printf("    draft: %s\n", cmdutil.Preview(event.DraftReply, 90))
			}
		}
		return nil
	},
}

var repliesQueueCmd = &cobra.Command{
	Use:   "queue",
	Short: "List reply events that still need action",
	RunE: func(cmd *cobra.Command, args []string) error {
		d, err := db.Open()
		if err != nil {
			return err
		}
		defer d.Close()

		events, err := sequence.ListReplyQueue(d, repliesLimit)
		if err != nil {
			return err
		}
		if repliesFormat == "json" {
			enc := json.NewEncoder(os.Stdout)
			enc.SetIndent("", "  ")
			return enc.Encode(events)
		}
		if len(events) == 0 {
			fmt.Println("  ✓ No reply-needed items")
			return nil
		}
		for _, event := range events {
			fmt.Printf("  [%s] %s\n", event.Classification, event.ContactEmail)
			fmt.Printf("    reply: %s | thread: %s\n", event.ID, event.ThreadID)
			if event.Subject != "" {
				fmt.Printf("    subject: %s\n", event.Subject)
			}
			if event.Snippet != "" {
				fmt.Printf("    snippet: %s\n", event.Snippet)
			}
			if event.AssignedTo != "" {
				fmt.Printf("    assigned: %s\n", event.AssignedTo)
			}
		}
		return nil
	},
}

var repliesDoneCmd = &cobra.Command{
	Use:   "done <reply-id>",
	Short: "Mark a reply-needed item as handled",
	Args:  cobra.ExactArgs(1),
	RunE: func(cmd *cobra.Command, args []string) error {
		d, err := db.Open()
		if err != nil {
			return err
		}
		defer d.Close()
		if err := sequence.MarkReplyHandled(d, args[0], repliesAssignedTo); err != nil {
			return err
		}
		fmt.Printf("  ✓ Marked %s as handled\n", args[0])
		return nil
	},
}

var repliesReopenCmd = &cobra.Command{
	Use:   "reopen <reply-id>",
	Short: "Reopen a handled reply-needed item",
	Args:  cobra.ExactArgs(1),
	RunE: func(cmd *cobra.Command, args []string) error {
		d, err := db.Open()
		if err != nil {
			return err
		}
		defer d.Close()
		if err := sequence.ReopenReply(d, args[0]); err != nil {
			return err
		}
		fmt.Printf("  ✓ Reopened %s\n", args[0])
		return nil
	},
}

var repliesDraftCmd = &cobra.Command{
	Use:   "draft <reply-id>",
	Short: "Store a draft response on a reply-needed item",
	Args:  cobra.ExactArgs(1),
	RunE: func(cmd *cobra.Command, args []string) error {
		d, err := db.Open()
		if err != nil {
			return err
		}
		defer d.Close()
		item, err := sequence.SaveReplyDraft(d, args[0], repliesDraftBody, repliesAssignedTo)
		if err != nil {
			return err
		}
		fmt.Printf("  ✓ Saved draft for %s (%s)\n", item.ID, item.ContactEmail)
		return nil
	},
}

func init() {
	repliesCmd.PersistentFlags().StringVar(&repliesFormat, "format", "", "Output format (json)")
	repliesListCmd.Flags().IntVar(&repliesLimit, "limit", 50, "Max results")
	repliesQueueCmd.Flags().IntVar(&repliesLimit, "limit", 50, "Max results")
	repliesDoneCmd.Flags().StringVar(&repliesAssignedTo, "assigned-to", "", "Optional owner recorded on the reply item")
	repliesDraftCmd.Flags().StringVar(&repliesAssignedTo, "assigned-to", "", "Optional owner recorded on the reply item")
	repliesDraftCmd.Flags().StringVar(&repliesDraftBody, "body", "", "Draft reply body to store on the item")
	repliesCmd.AddCommand(repliesSyncCmd)
	repliesCmd.AddCommand(repliesListCmd)
