		if err := json.Unmarshal(data, &entries); err != nil {
			return fmt.Errorf("parsing JSON: %w", err)
		}

		d, err := db.Open()
		if err != nil {
			return err
		}
		defer d.Close()

		reclassified := 0
		unchanged := 0
		for _, entry := range entries {
			old, err := sequence.ReclassifyReply(d, entry.ID, entry.Classification)
			if err != nil {
				return fmt.Errorf("reclassifying %s: %w", entry.ID, err)
			}
			if old != entry.Classification {
				reclassified++
			} else {
				unchanged++
			}
		}

		if repliesFormat == "json" {
			enc := json.NewEncoder(os.Stdout)
			enc.SetIndent("", "  ")
			return enc.Encode(map[string]int{"reclassified": reclassified, "unchanged": unchanged})
		}
		fmt.Printf("  Reclassified: %d | Unchanged: %d\n", reclassified, unchanged)
		return nil
	},
}

func init() {
	repliesCmd.PersistentFlags().StringVar(&repliesFormat, "format", "", "Output format (json)")
	repliesListCmd.Flags().IntVar(&repliesLimit, "limit", 50, "Max results")
	repliesQueueCmd.Flags().IntVar(&repliesLimit, "limit", 50, "Max results")
	repliesDoneCmd.Flags().StringVar(&repliesAssignedTo, "assigned-to", "", "Optional owner recorded on the reply item")
	repliesDraftCmd.Flags().StringVar(&repliesAssignedTo, "assigned-to", "", "Optional owner recorded on the reply item")
	repliesDraftCmd.Flags().StringVar(&repliesDraftBody, "body", "", "Draft reply body to store on the item")
	repliesCmd.AddCommand(repliesSyncCmd)
	repliesCmd.AddCommand(repliesListCmd)
	repliesCmd.AddCommand(repliesQueueCmd)
	repliesCmd.AddCommand(repliesDoneCmd)
	repliesCmd.AddCommand(repliesReopenCmd)
	repliesCmd.AddCommand(repliesDraftCmd)
	repliesCmd.AddCommand(repliesClassifyCmd)
}

