package pipeline

import (
	"database/sql"
	"fmt"
	"math"
	"time"
)

// PipelineStatus is the consolidated pipeline state returned by Status().
type PipelineStatus struct {
	GeneratedAt string `json:"generated_at"`

	NewOutreach NewOutreachStatus `json:"new_outreach"`
	FollowUps   FollowUpStatus    `json:"follow_ups"`
	Pipeline    PipelineFunnel    `json:"pipeline"`
	Capacity    CapacityInfo      `json:"capacity"`

	ByPersona []PersonaPipeline `json:"by_persona,omitempty"`
	BySource  []SourcePipeline  `json:"by_source,omitempty"`

	Nudge      *SmartNudge `json:"nudge,omitempty"`
	LastSyncAt string      `json:"last_sync_at,omitempty"`
}

// NewOutreachStatus tracks first-touch capacity and usage.
type NewOutreachStatus struct {
	SentToday  int `json:"sent_today"`
	DailyLimit int `json:"daily_limit"`
	Ready      int `json:"ready"`
	Active     int `json:"active"`
}

// FollowUpStatus tracks follow-up activity (uncapped, separate from new outreach).
type FollowUpStatus struct {
	SentToday int `json:"sent_today"`
	DueToday  int `json:"due_today"`
	Overdue   int `json:"overdue"`
}

// PipelineFunnel tracks the full prospect funnel.
type PipelineFunnel struct {
	Sourced    int `json:"sourced"`
	Researched int `json:"researched"`
	Ready      int `json:"ready"`
	Contacted  int `json:"contacted"`
	Replied    int `json:"replied"`
}

// CapacityInfo tracks how long the current pool will last.
type CapacityInfo struct {
	DaysOfLeads    int `json:"days_of_leads"`
	TotalDailyCap  int `json:"total_daily_cap"`
	TotalFollowCap int `json:"total_follow_up_cap"`
}

// PersonaPipeline breaks down the funnel by persona.
type PersonaPipeline struct {
	Persona    string `json:"persona"`
	Sourced    int    `json:"sourced"`
	Researched int    `json:"researched"`
	Ready      int    `json:"ready"`
	Contacted  int    `json:"contacted"`
	Replied    int    `json:"replied"`
}

// SourcePipeline breaks down pipeline by contact source with effectiveness.
type SourcePipeline struct {
	Source    string  `json:"source"`
	Sourced   int     `json:"sourced"`
	Contacted int     `json:"contacted"`
	Replied   int     `json:"replied"`
	ReplyRate float64 `json:"reply_rate"`
}

// SmartNudge is the diagnosed pipeline problem and recommended action.
type SmartNudge struct {
	Type    string `json:"type"`
	Message string `json:"message"`
	Action  string `json:"action,omitempty"`
}

// Nudge types.
const (
	NudgeEmptyPipeline      = "empty_pipeline"
	NudgeMessagingProblem   = "messaging_problem"
	NudgeResearchBottleneck = "research_bottleneck"
	NudgePoolDraining       = "pool_draining"
	NudgeCapacityWasted     = "capacity_wasted"
	NudgePersonaImbalance   = "persona_imbalance"
	NudgeHealthy            = "healthy"
)

// Status gathers pipeline state from the database in a single call.
func Status(d *sql.DB, now time.Time) (*PipelineStatus, error) {
	ps := &PipelineStatus{
		GeneratedAt: now.Format(time.RFC3339),
	}

	today := now.Format("2006-01-02")

	// Pipeline funnel counts
	d.QueryRow("SELECT COUNT(*) FROM contacts").Scan(&ps.Pipeline.Sourced)
	d.QueryRow("SELECT COUNT(DISTINCT contact_email) FROM research_dossiers").Scan(&ps.Pipeline.Researched)
	d.QueryRow("SELECT COUNT(DISTINCT contact_email) FROM sequence_enrollments").Scan(&ps.Pipeline.Contacted)
	d.QueryRow("SELECT COUNT(DISTINCT contact_email) FROM reply_events").Scan(&ps.Pipeline.Replied)

	// Ready = has dossier but never enrolled in a sequence
	d.QueryRow(`
		SELECT COUNT(DISTINCT rd.contact_email)
		FROM research_dossiers rd
		LEFT JOIN sequence_enrollments se ON se.contact_email = rd.contact_email
		WHERE se.id IS NULL
	`).Scan(&ps.Pipeline.Ready)

	// New outreach: today's first touches
	d.QueryRow(`
		SELECT COALESCE(SUM(first_touches_sent), 0)
		FROM mailbox_daily_usage
		WHERE usage_day = ?
	`, today).Scan(&ps.NewOutreach.SentToday)

	// Daily limit: sum of active mailbox first-touch caps
	d.QueryRow(`
		SELECT COALESCE(SUM(first_touch_daily_cap), 0)
		FROM mailboxes
		WHERE status = 'active'
	`).Scan(&ps.NewOutreach.DailyLimit)

	ps.NewOutreach.Ready = ps.Pipeline.Ready
	ps.NewOutreach.Active = ps.Pipeline.Sourced - ps.Pipeline.Contacted

	// Follow-ups: today's sends
	d.QueryRow(`
		SELECT COALESCE(SUM(follow_ups_sent), 0)
		FROM mailbox_daily_usage
		WHERE usage_day = ?
	`, today).Scan(&ps.FollowUps.SentToday)

	// Follow-ups: due today
	d.QueryRow(`
		SELECT COUNT(*)
		FROM follow_up_tasks
		WHERE status = 'open' AND date(due_at) <= ?
	`, today).Scan(&ps.FollowUps.DueToday)

	// Follow-ups: overdue (due before now)
	nowStr := now.Format("2006-01-02T15:04:05")
	d.QueryRow(`
		SELECT COUNT(*)
		FROM follow_up_tasks
		WHERE status = 'open' AND due_at < ?
	`, nowStr).Scan(&ps.FollowUps.Overdue)

	// Capacity
	d.QueryRow(`
		SELECT COALESCE(SUM(follow_up_daily_cap), 0)
		FROM mailboxes
		WHERE status = 'active'
	`).Scan(&ps.Capacity.TotalFollowCap)
	ps.Capacity.TotalDailyCap = ps.NewOutreach.DailyLimit
	if ps.NewOutreach.DailyLimit > 0 {
		ps.Capacity.DaysOfLeads = int(math.Ceil(float64(ps.Pipeline.Ready) / float64(ps.NewOutreach.DailyLimit)))
	}

	// Last sync
	d.QueryRow(`
		SELECT COALESCE(MAX(last_sync_at), '')
		FROM connectors
		WHERE status = 'connected'
	`).Scan(&ps.LastSyncAt)

	// Per-source effectiveness
	ps.BySource = querySourcePipeline(d)

	// Diagnose
	ps.Nudge = DiagnoseNudge(ps)

	return ps, nil
}

func querySourcePipeline(d *sql.DB) []SourcePipeline {
	rows, err := d.Query(`
		SELECT c.source,
			COUNT(*) as sourced,
			COUNT(DISTINCT se.contact_email) as contacted,
			COUNT(DISTINCT re.contact_email) as replied
		FROM contacts c
		LEFT JOIN sequence_enrollments se ON se.contact_email = c.email
		LEFT JOIN reply_events re ON re.contact_email = c.email
		GROUP BY c.source
		ORDER BY sourced DESC
	`)
	if err != nil {
		return nil
	}
	defer rows.Close()

	var sources []SourcePipeline
	for rows.Next() {
		var sp SourcePipeline
		if err := rows.Scan(&sp.Source, &sp.Sourced, &sp.Contacted, &sp.Replied); err != nil {
			continue
		}
		if sp.Contacted > 0 {
			sp.ReplyRate = float64(sp.Replied) / float64(sp.Contacted)
		}
		sources = append(sources, sp)
	}
	return sources
}

// DiagnoseNudge checks pipeline health and returns the highest-priority nudge.
// Priority order: empty > messaging problem > research bottleneck > pool draining > capacity wasted > persona imbalance > healthy.
func DiagnoseNudge(ps *PipelineStatus) *SmartNudge {
	// 1. Empty pipeline
	if ps.Pipeline.Sourced == 0 {
		return &SmartNudge{
			Type:    NudgeEmptyPipeline,
			Message: "No leads in pipeline. Run /nurge:prospects to build a list.",
			Action:  "/nurge:prospects",
		}
	}

	// 2. Messaging problem: 50+ contacted, 0 replies
	if ps.Pipeline.Contacted >= 50 && ps.Pipeline.Replied == 0 {
		return &SmartNudge{
			Type:    NudgeMessagingProblem,
			Message: fmt.Sprintf("0 replies from %d sends. Review messaging before sourcing more.", ps.Pipeline.Contacted),
			Action:  "/nurge:review",
		}
	}

	// 3. Research bottleneck: many sourced, few ready, lots unresearched
	unresearched := ps.Pipeline.Sourced - ps.Pipeline.Researched - ps.Pipeline.Contacted
	if unresearched < 0 {
		unresearched = 0
	}
	if ps.Pipeline.Sourced > 10 && ps.Pipeline.Ready < 3 && unresearched > ps.Pipeline.Ready*5 {
		return &SmartNudge{
			Type:    NudgeResearchBottleneck,
			Message: fmt.Sprintf("%d leads need research before they're ready to send.", unresearched),
			Action:  "/nurge:research",
		}
	}

	// 4. Pool draining: ready leads < 1 week of daily capacity
	if ps.NewOutreach.DailyLimit > 0 && ps.Capacity.DaysOfLeads > 0 && ps.Capacity.DaysOfLeads < 7 {
		msg := fmt.Sprintf("At your current pace, you'll run out of leads in %d days.", ps.Capacity.DaysOfLeads)
		bestSource := bestSourceByReplyRate(ps.BySource)
		if bestSource != "" {
			msg += fmt.Sprintf(" Best source: %s.", bestSource)
		}
		return &SmartNudge{
			Type:    NudgePoolDraining,
			Message: msg,
			Action:  "/nurge:prospects",
		}
	}

	// 5. Capacity wasted: ready < daily limit
	if ps.NewOutreach.DailyLimit > 0 && ps.NewOutreach.Ready < ps.NewOutreach.DailyLimit {
		msg := fmt.Sprintf("You have capacity for %d more sends but only %d ready leads.",
			ps.NewOutreach.DailyLimit-ps.NewOutreach.SentToday, ps.NewOutreach.Ready)
		bestSource := bestSourceByReplyRate(ps.BySource)
		if bestSource != "" {
			msg += fmt.Sprintf(" Best source: %s.", bestSource)
		}
		return &SmartNudge{
			Type:    NudgeCapacityWasted,
			Message: msg,
		}
	}

	// 6. Persona imbalance (checked via ByPersona if populated)
	for _, pp := range ps.ByPersona {
		if pp.Sourced == 0 {
			return &SmartNudge{
				Type:    NudgePersonaImbalance,
				Message: fmt.Sprintf("Your %s pipeline is empty. Source leads for this persona.", pp.Persona),
				Action:  "/nurge:prospects",
			}
		}
	}

	// 7. Healthy
	return &SmartNudge{
		Type:    NudgeHealthy,
		Message: "Pipeline is healthy.",
	}
}

func bestSourceByReplyRate(sources []SourcePipeline) string {
	var best string
	var bestRate float64
	for _, sp := range sources {
		if sp.Contacted >= 5 && sp.ReplyRate > bestRate {
			bestRate = sp.ReplyRate
			best = sp.Source
		}
	}
	if best == "" || bestRate == 0 {
		return ""
	}
	return fmt.Sprintf("%s (%d%% reply rate)", best, int(bestRate*100))
}

