				ContactName:     name,
				SignalType:      sig.Type,
				Summary:         sig.Summary,
				DetectedAt:      sig.DetectedAt,
				DaysOld:         daysOld,
				CurrentStrength: math.Round(currentStrength*100) / 100,
			})
		}
	}
	return decaying
}

