		}
	}

	// 4. Pool draining: ready leads < 1 week of daily capacity
	if ps.NewOutreach.DailyLimit > 0 && ps.Capacity.DaysOfLeads > 0 && ps.Capacity.DaysOfLeads < 7 {
		msg := fmt.Sprintf("At your current pace, you'll run out of leads in %d days.", ps.Capacity.DaysOfLeads)
		bestSource := bestSourceByReplyRate(ps.BySource)
		if bestSource != "" {
