}

func runContactSignal(cmd *cobra.Command, args []string) error {
	if signalEmail == "" {
		return fmt.Errorf("--email is required")
	}

	data, err := io.ReadAll(os.Stdin)
	if err != nil {
		return fmt.Errorf("reading stdin: %w", err)
	}
	if len(data) == 0 {
		return fmt.Errorf("no input on stdin")
	}

	var newSignals []signalEntry
	if err := json.Unmarshal(data, &newSignals); err != nil {
		return fmt.Errorf("parsing JSON: %w", err)
	}

	// Fill defaults
	now := time.Now().UTC().Format(time.RFC3339)
	for i := range newSignals {
		if newSignals[i].DetectedAt == "" {
			newSignals[i].DetectedAt = now
		}
		if newSignals[i].Strength == 0 {
			newSignals[i].Strength = 0.8
		}
		if newSignals[i].DecayDays == 0 {
			newSignals[i].DecayDays = 90
		}
		if newSignals[i].Source == "" {
			newSignals[i].Source = "user_reported"
		}
	}

	d, err := db.Open()
	if err != nil {
		return err
	}
	defer d.Close()

	email := strings.ToLower(strings.TrimSpace(signalEmail))

	// Load existing signals
	var existingJSON string
	d.QueryRow(`SELECT COALESCE(signals, '[]') FROM contacts WHERE lower(email) = ?`, email).Scan(&existingJSON)
	if existingJSON == "" {
		existingJSON = "[]"
	}

	var existing []signalEntry
	json.Unmarshal([]byte(existingJSON), &existing)

	// Merge: deduplicate by type+summary
	seen := make(map[string]bool)
	for _, s := range existing {
		seen[s.Type+"|"+s.Summary] = true
	}
	for _, s := range newSignals {
		key := s.Type + "|" + s.Summary
		if !seen[key] {
			existing = append(existing, s)
			seen[key] = true
		}
	}

	merged, _ := json.Marshal(existing)
	_, err = d.Exec(`UPDATE contacts SET signals = ?, updated_at = datetime('now') WHERE lower(email) = ?`,
		string(merged), email)
	if err != nil {
		return fmt.Errorf("updating signals: %w", err)
	}

	if signalFormat == "json" {
		enc := json.NewEncoder(os.Stdout)
		enc.SetIndent("", "  ")
		return enc.Encode(map[string]any{
			"email":        email,
			"total_signals": len(existing),
			"added":        len(newSignals),
		})
	}
	fmt.Printf("  Updated signals for %s (%d total, %d new)\n", email, len(existing), len(newSignals))
	return nil
}

func init() {
	contactSignalCmd.Flags().StringVar(&signalEmail, "email", "", "Contact email address")
	contactSignalCmd.Flags().StringVar(&signalFormat, "format", "", "Output format (json)")
	contactCmd.AddCommand(contactSignalCmd)
}

