342→func buildStrategicMemoryPromptContext(memories []session.StrategicMemory, staleSkills []session.StaleSkill) string {
343→	if len(memories) == 0 && len(staleSkills) == 0 {
344→		return ""
345→	}
346→
347→	var b strings.Builder
348→	if len(memories) > 0 {
349→		b.WriteString("Strategic memory updates:\n")
350→		for _, memory := range memories {
351→			fmt.Fprintf(&b, "- %s", memory.Summary)
352→			if len(memory.AffectedSkills) > 0 {
353→				fmt.Fprintf(&b, " Affects: %s.", strings.Join(memory.AffectedSkills, ", "))
354→			}
355→			b.WriteString("\n")
356→		}
357→	}
358→
359→	if len(staleSkills) > 0 {
360→		b.WriteString("Skills likely stale:\n")
361→		for _, item := range staleSkills {
362→			fmt.Fprintf(&b, "- %s: %s\n", item.SkillName, strings.Join(item.Reasons, "; "))
363→		}
364→		b.WriteString("If you refresh a skill, persist the new version with `nurge skills save <skill-name> --file .claude/skills/<skill-name>/SKILL.md`. Use `nurge skills stale --format json` for the full refresh list and `nurge memory list --format json` for the underlying strategic memory.\n")
365→	}
366→
367→	return b.String()
368→}
