370→func shortSyncError(err error) string {
371→	if err == nil {
372→		return ""
373→	}
374→	message := strings.TrimSpace(err.Error())
375→	if len(message) > 120 {
376→		return message[:117] + "..."
377→	}
378→	return message
379→}
380→
381→func pluralSuffix(count int, forms ...string) string {
382→	if len(forms) == 2 {
383→		if count == 1 {
384→			return forms[0]
385→		}
386→		return forms[1]
387→	}
388→	if count == 1 {
389→		return ""
390→	}
391→	return "s"
392→}
393→
394→func capitalize(s string) string {
395→	if s == "" {
396→		return s
397→	}
398→	return strings.ToUpper(s[:1]) + s[1:]
399→}
400→
401→func formatCount(n int) string {
402→	if n >= 1000 {
403→		return fmt.Sprintf("%d,%03d", n/1000, n%1000)
404→	}
405→	return fmt.Sprintf("%d", n)
406→}
