  1→package data
  2→
  3→import (
  4→	"encoding/json"
  5→	"fmt"
  6→	"io"
  7→	"os"
  8→	"strings"
  9→	"time"
 10→
 11→	"github.com/spf13/cobra"
 12→	"github.com/usenurge/nurgesh/internal/db"
 13→)
 14→
 15→var signalEmail string
 16→var signalFormat string
 17→
 18→var contactCmd = &cobra.Command{
 19→	Use:   "contact",
 20→	Short: "Contact management commands",
 21→}
 22→
 23→var contactSignalCmd = &cobra.Command{
 24→	Use:   "signal",
 25→	Short: "Add or update signals for a contact from stdin",
 26→	Long:  `Reads a JSON array of signals from stdin and merges them into the contact's signals field.`,
 27→	RunE:  runContactSignal,
 28→}
 29→
 30→type signalEntry struct {
 31→	Type       string  `json:"type"`
 32→	Summary    string  `json:"summary"`
 33→	Source     string  `json:"source"`
 34→	Strength   float64 `json:"strength"`
 35→	DetectedAt string  `json:"detected_at"`
 36→	DecayDays  int     `json:"decay_days"`
 37→}
 38→
 39→func runContactSignal(cmd *cobra.Command, args []string) error {
 40→	if signalEmail == "" {
 41→		return fmt.Errorf("--email is required")
 42→	}
 43→
 44→	data, err := io.ReadAll(os.Stdin)
 45→	if err != nil {
 46→		return fmt.Errorf("reading stdin: %w", err)
 47→	}
 48→	if len(data) == 0 {
 49→		return fmt.Errorf("no input on stdin")
 50→	}
 51→
 52→	var newSignals []signalEntry
 53→	if err := json.Unmarshal(data, &newSignals); err != nil {
 54→		return fmt.Errorf("parsing JSON: %w", err)
 55→	}
 56→
 57→	// Fill defaults
 58→	now := time.Now().UTC().Format(time.RFC3339)
 59→	for i := range newSignals {
 60→		if newSignals[i].DetectedAt == "" {
 61→			newSignals[i].DetectedAt = now
 62→		}
 63→		if newSignals[i].Strength == 0 {
 64→			newSignals[i].Strength = 0.8
 65→		}
 66→		if newSignals[i].DecayDays == 0 {
 67→			newSignals[i].DecayDays = 90
 68→		}
 69→		if newSignals[i].Source == "" {
 70→			newSignals[i].Source = "user_reported"
 71→		}
 72→	}
 73→
 74→	d, err := db.Open()
 75→	if err != nil {
 76→		return err
 77→	}
 78→	defer d.Close()
 79→
 80→	email := strings.ToLower(strings.TrimSpace(signalEmail))
 81→
 82→	// Load existing signals
 83→	var existingJSON string
 84→	d.QueryRow(`SELECT COALESCE(signals, '[]') FROM contacts WHERE lower(email) = ?`, email).Scan(&existingJSON)
 85→	if existingJSON == "" {
 86→		existingJSON = "[]"
 87→	}
 88→
 89→	var existing []signalEntry
 90→	json.Unmarshal([]byte(existingJSON), &existing)
 91→
 92→	// Merge: deduplicate by type+summary
 93→	seen := make(map[string]bool)
 94→	for _, s := range existing {
 95→		seen[s.Type+"|"+s.Summary] = true
 96→	}
 97→	for _, s := range newSignals {
 98→		key := s.Type + "|" + s.Summary
 99→		if !seen[key] {
100→			existing = append(existing, s)
101→			seen[key] = true
102→		}
103→	}
104→
105→	merged, _ := json.Marshal(existing)
106→	_, err = d.Exec(`UPDATE contacts SET signals = ?, updated_at = datetime('now') WHERE lower(email) = ?`,
107→		string(merged), email)
108→	if err != nil {
109→		return fmt.Errorf("updating signals: %w", err)
110→	}
111→
112→	if signalFormat == "json" {
113→		enc := json.NewEncoder(os.Stdout)
114→		enc.SetIndent("", "  ")
115→		return enc.Encode(map[string]any{
116→			"email":        email,
117→			"total_signals": len(existing),
118→			"added":        len(newSignals),
119→		})
120→	}
121→	fmt.Printf("  Updated signals for %s (%d total, %d new)\n", email, len(existing), len(newSignals))
122→	return nil
123→}
124→
125→func init() {
126→	contactSignalCmd.Flags().StringVar(&signalEmail, "email", "", "Contact email address")
127→	contactSignalCmd.Flags().StringVar(&signalFormat, "format", "", "Output format (json)")
128→	contactCmd.AddCommand(contactSignalCmd)
129→}
