170→// isKnownCommand checks if name matches any registered subcommand.
171→func isKnownCommand(name string) bool {
172→	for _, c := range rootCmd.Commands() {
173→		if c.Name() == name {
174→			return true
175→		}
176→		for _, alias := range c.Aliases {
177→			if alias == name {
178→				return true
179→			}
180→		}
181→	}
182→	return name == "help" || name == "completion"
