185→func Execute() error {
186→	// Allow "nurge my-outbound" as shorthand for "nurge init my-outbound".
187→	// Cobra rejects unknown subcommands before RunE runs, so we rewrite args
188→	// when the first arg isn't a known subcommand or flag.
189→	if len(os.Args) > 1 {
190→		first := os.Args[1]
191→		if !strings.HasPrefix(first, "-") && !isKnownCommand(first) {
192→			os.Args = append([]string{os.Args[0], "init"}, os.Args[1:]...)
193→		}
194→	}
195→
196→	// Start async update check before stdout wrapping (uses stderr, no interaction).
197→	type updateResult struct {
198→		info *update.UpdateInfo
199→	}
200→	updateCh := make(chan updateResult, 1)
201→	cmdName := resolveCommandName()
202→	if cmdutil.BuildVersion != "dev" && cmdName != "update" && cmdName != "version" {
203→		go func() {
204→			ctx, cancel := context.WithTimeout(context.Background(), 2*time.Second)
205→			defer cancel()
206→			info, _ := update.CheckForUpdate(ctx, cmdutil.BuildVersion)
207→			updateCh <- updateResult{info: info}
208→		}()
209→	}
210→
211→	// Wrap stdout with a counting writer to measure output size.
212→	cw := metrics.NewCountingWriter(os.Stdout)
213→	rootCmd.SetOut(cw)
214→	origStdout := os.Stdout
215→	r, w, _ := os.Pipe()
216→	os.Stdout = w
217→
218→	// Copy pipe output to counting writer in background.
219→	done := make(chan struct{})
220→	go func() {
221→		buf := make([]byte, 4096)
222→		for {
223→			n, err := r.Read(buf)
224→			if n > 0 {
225→				cw.Write(buf[:n])
226→			}
227→			if err != nil {
228→				break
229→			}
230→		}
231→		close(done)
232→	}()
233→
234→	err := rootCmd.Execute()
235→
236→	// Restore stdout and flush.
237→	w.Close()
238→	<-done
239→	os.Stdout = origStdout
240→
241→	// Print update notification if available (to stderr, so --format json is clean).
242→	select {
243→	case r := <-updateCh:
244→		if r.info != nil {
245→			fmt.Fprintf(os.Stderr, "\n→ nurge %s available. Run: nurge update\n", r.info.LatestVersion)
246→		}
247→	default:
248→	}
249→
250→	// Log metrics if we're in a nurge project and this isn't the init/metrics command.
251→	if cmdName != "" && cmdName != "init" && cmdName != "metrics" && cmdName != "version" && db.Exists() {
252→		if d, dbErr := db.Open(); dbErr == nil {
253→			_ = metrics.EnsureTable(d)
254→			_ = metrics.Log(d, metrics.SessionID(), cmdName, cw.Count())
255→			d.Close()
256→		}
257→	}
258→
259→	return err
260→}
