270→// resolveCommandName returns the full command path (e.g. "emails list", "skills write").
271→func resolveCommandName() string {
272→	if len(os.Args) < 2 {
273→		return "init"
274→	}
275→	// Build command name from args, skipping flags.
276→	var parts []string
277→	for _, arg := range os.Args[1:] {
278→		if strings.HasPrefix(arg, "-") {
279→			break
280→		}
281→		parts = append(parts, arg)
282→	}
283→	if len(parts) == 0 {
284→		return "init"
285→	}
286→	return strings.Join(parts, " ")
287→}
