213→var repliesClassifyCmd = &cobra.Command{
214→	Use:   "classify",
215→	Short: "Reclassify reply events from stdin (JSON array)",
216→	Long:  `Reads a JSON array of {"id":"reply:xxx","classification":"interested"} from stdin and reclassifies each reply, triggering cascading logic.`,
217→	RunE: func(cmd *cobra.Command, args []string) error {
218→		data, err := io.ReadAll(os.Stdin)
219→		if err != nil {
220→			return fmt.Errorf("reading stdin: %w", err)
221→		}
222→		if len(data) == 0 {
223→			return fmt.Errorf("no input on stdin")
224→		}
225→
226→		var entries []struct {
227→			ID             string `json:"id"`
228→			Classification string `json:"classification"`
229→		}
230→		if err := json.Unmarshal(data, &entries); err != nil {
231→			return fmt.Errorf("parsing JSON: %w", err)
232→		}
233→
234→		d, err := db.Open()
235→		if err != nil {
236→			return err
237→		}
238→		defer d.Close()
239→
240→		reclassified := 0
241→		unchanged := 0
242→		for _, entry := range entries {
243→			old, err := sequence.ReclassifyReply(d, entry.ID, entry.Classification)
244→			if err != nil {
245→				return fmt.Errorf("reclassifying %s: %w", entry.ID, err)
246→			}
247→			if old != entry.Classification {
248→				reclassified++
249→			} else {
250→				unchanged++
251→			}
252→		}
253→
254→		if repliesFormat == "json" {
255→			enc := json.NewEncoder(os.Stdout)
256→			enc.SetIndent("", "  ")
257→			return enc.Encode(map[string]int{"reclassified": reclassified, "unchanged": unchanged})
258→		}
259→		fmt.Printf("  Reclassified: %d | Unchanged: %d\n", reclassified, unchanged)
260→		return nil
261→	},
262→}
