 11→func buildBanner(s *sessionStatus) string {
 12→	var b strings.Builder
 13→	ver := fmt.Sprintf("nurge %s", cmdutil.BuildVersion)
 14→
 15→	// Line 1: Powered by Nurge
 16→	b.WriteString("\n\nPowered by Nurge\n")
 17→	// Line 2: Version
 18→	fmt.Fprintf(&b, "  %s\n", ver)
 19→
 20→	if !s.configLoaded {
 21→		b.WriteString("  Run: nurge to get started")
 22→		return b.String()
 23→	}
 24→
 25→	// --- Pre-setup: no connectors yet ---
 26→	hasConnectors := false
 27→	for _, c := range s.connectors {
 28→		if c.Connected {
 29→			hasConnectors = true
 30→			break
 31→		}
 32→	}
 33→	if !hasConnectors {
 34→		b.WriteString("  Run /nurge:setup to connect your email and get started.")
 35→		return b.String()
 36→	}
 37→
 38→	// --- Setup in progress ---
 39→	if !s.setupCompleted {
 40→		name := s.settings["user.name"]
 41→		if name != "" {
 42→			fmt.Fprintf(&b, "  Hey %s, setup in progress.\n", name)
 43→		} else {
 44→			b.WriteString("  Setup in progress.\n")
 45→		}
 46→		b.WriteString("  Run /nurge:setup to continue where you left off.")
 47→		return b.String()
 48→	}
 49→
 50→	// --- Post-setup: compact rotating dashboard ---
 51→	name := s.settings["user.name"]
 52→	if name != "" {
 53→		fmt.Fprintf(&b, "  Hey %s\n", name)
 54→	}
 55→
 56→	if syncLine := buildSyncBannerLine(s.startSync); syncLine != "" {
 57→		fmt.Fprintf(&b, "  %s\n", syncLine)
 58→	}
 59→	if refreshLine := buildSkillRefreshBannerLine(s.staleSkills); refreshLine != "" {
 60→		fmt.Fprintf(&b, "  %s\n", refreshLine)
 61→	}
 62→
 63→	// Pipeline dashboard (replaces rotating slots)
 64→	if ps := s.pipelineStatus; ps != nil {
 65→		fmt.Fprintf(&b, "  New outreach: %d/%d sent | %d ready | %d active\n",
 66→			ps.NewOutreach.SentToday, ps.NewOutreach.DailyLimit,
 67→			ps.NewOutreach.Ready, ps.NewOutreach.Active)
 68→		fmt.Fprintf(&b, "  Follow-ups:  %d sent today | %d due",
 69→			ps.FollowUps.SentToday, ps.FollowUps.DueToday)
 70→		if ps.FollowUps.Overdue > 0 {
 71→			fmt.Fprintf(&b, " (%d overdue)", ps.FollowUps.Overdue)
 72→		}
 73→		b.WriteString("\n")
 74→		fmt.Fprintf(&b, "  Pipeline:    sourced %d | researched %d | ready %d | contacted %d | replied %d\n",
 75→			ps.Pipeline.Sourced, ps.Pipeline.Researched, ps.Pipeline.Ready,
 76→			ps.Pipeline.Contacted, ps.Pipeline.Replied)
 77→
 78→		// Sources line (only if 2+ sources)
 79→		if len(ps.BySource) >= 2 {
 80→			fmt.Fprintf(&b, "  Sources:     ")
 81→			for i, sp := range ps.BySource {
 82→				if i > 0 {
 83→					fmt.Fprintf(&b, " | ")
 84→				}
 85→				if sp.Contacted > 0 {
 86→					fmt.Fprintf(&b, "%s %d (%d%% reply)", sp.Source, sp.Sourced, int(sp.ReplyRate*100))
 87→				} else {
 88→					fmt.Fprintf(&b, "%s %d", sp.Source, sp.Sourced)
 89→				}
 90→			}
 91→			b.WriteString("\n")
 92→		}
 93→
 94→		// Decaying signals line
 95→		if len(ps.DecayingSignals) > 0 {
 96→			oldest := ps.DecayingSignals[0]
 97→			for _, ds := range ps.DecayingSignals {
 98→				if ds.DaysOld > oldest.DaysOld {
 99→					oldest = ds
100→				}
101→			}
102→			fmt.Fprintf(&b, "  Signals:     %d cooling (oldest: %d days)\n", len(ps.DecayingSignals), oldest.DaysOld)
103→		}
104→
105→		if ps.Nudge != nil && ps.Nudge.Type != "healthy" {
106→			fmt.Fprintf(&b, "  -> %s\n", ps.Nudge.Message)
107→		}
108→	} else {
109→		// Fallback: basic stats when pipeline data unavailable
110→		if s.weeklyStats != nil && s.weeklyStats.OutboundSent > 0 {
111→			fmt.Fprintf(&b, "  This week: %d emails sent", s.weeklyStats.OutboundSent)
112→			if s.weeklyStats.UniqueContacts > 0 {
113→				fmt.Fprintf(&b, " -> %d contacts", s.weeklyStats.UniqueContacts)
114→			}
115→			b.WriteString("\n")
116→		}
117→		fmt.Fprintf(&b, "  %s emails synced | %d skills active\n", formatCount(s.emailTotal), s.skillCount)
118→	}
119→
120→	return b.String()
121→}
