248→func buildSyncBannerLine(report *sessionSyncReport) string {
249→	if report == nil || !report.Attempted {
250→		return ""
251→	}
252→	if report.Error != "" {
253→		return "Remote sync unavailable — using last local state"
254→	}
255→	if report.RowsUpserted == 0 {
256→		return ""
257→	}
258→
259→	parts := []string{}
260→	if report.Delta != nil {
261→		if report.Delta.TasksSent > 0 {
262→			parts = append(parts, fmt.Sprintf("%d follow-up%s sent", report.Delta.TasksSent, pluralSuffix(report.Delta.TasksSent)))
263→		}
264→		if report.Delta.RepliesNeedingAttention > 0 {
265→			parts = append(parts, fmt.Sprintf("%d repl%s need attention", report.Delta.RepliesNeedingAttention, pluralSuffix(report.Delta.RepliesNeedingAttention, "y", "ies")))
266→		}
267→		if report.Delta.TasksFailed > 0 {
268→			parts = append(parts, fmt.Sprintf("%d send failure%s", report.Delta.TasksFailed, pluralSuffix(report.Delta.TasksFailed)))
269→		}
270→		if len(report.Delta.AuthExpiredMailboxes) > 0 {
271→			parts = append(parts, fmt.Sprintf("%d mailbox reconnect%s needed", len(report.Delta.AuthExpiredMailboxes), pluralSuffix(len(report.Delta.AuthExpiredMailboxes))))
272→		}
273→	}
274→	if len(parts) == 0 {
275→		return fmt.Sprintf("Synced %d remote update%s", report.RowsUpserted, pluralSuffix(report.RowsUpserted))
276→	}
277→	return "While you were away: " + strings.Join(parts, " | ")
278→}
