280→func buildSyncPromptContext(report *sessionSyncReport) string {
281→	if report == nil || !report.Attempted {
282→		return ""
283→	}
284→
285→	var b strings.Builder
286→	if report.Error != "" {
287→		fmt.Fprintf(&b, "Remote sync status: unavailable (%s). Work from local state and avoid assuming cloud execution has fully caught up.\n", report.Error)
288→		return b.String()
289→	}
290→
291→	if report.RowsUpserted == 0 {
292→		b.WriteString("Remote sync status: no new execution-state changes since the last session.\n")
293→		return b.String()
294→	}
295→
296→	fmt.Fprintf(&b, "Remote sync status: pulled %d row%s across %d table%s.\n",
297→		report.RowsUpserted,
298→		pluralSuffix(report.RowsUpserted),
299→		report.TablesUpdated,
300→		pluralSuffix(report.TablesUpdated),
301→	)
302→
303→	if report.Delta == nil {
304→		return b.String()
305→	}
306→
307→	if report.Delta.TasksSent > 0 {
308→		fmt.Fprintf(&b, "Remote sends completed: %d.\n", report.Delta.TasksSent)
309→	}
310→	if report.Delta.TasksFailed > 0 {
311→		fmt.Fprintf(&b, "Remote send failures: %d. Check `nurge tasks list` and `nurge sends list` before advancing sequences.\n", report.Delta.TasksFailed)
312→	}
313→	if report.Delta.RepliesNeedingAttention > 0 {
314→		fmt.Fprintf(&b, "Replies needing attention: %d. Check `nurge replies queue` early in the session.\n", report.Delta.RepliesNeedingAttention)
315→		for _, item := range report.Delta.RecentReplies {
316→			if strings.TrimSpace(item.Subject) != "" {
317→				fmt.Fprintf(&b, "- Reply: %s (%s) — %s\n", item.ContactEmail, item.Classification, item.Subject)
318→				continue
319→			}
320→			fmt.Fprintf(&b, "- Reply: %s (%s)\n", item.ContactEmail, item.Classification)
321→		}
322→	}
323→	if report.Delta.EnrollmentsStopped > 0 {
324→		fmt.Fprintf(&b, "Enrollments stopped remotely: %d.\n", report.Delta.EnrollmentsStopped)
325→	}
326→	if report.Delta.EnrollmentsCompleted > 0 {
327→		fmt.Fprintf(&b, "Enrollments completed remotely: %d.\n", report.Delta.EnrollmentsCompleted)
328→	}
329→	if report.Delta.SuppressionsAdded > 0 {
330→		fmt.Fprintf(&b, "Suppressions added remotely: %d.\n", report.Delta.SuppressionsAdded)
331→	}
332→	if len(report.Delta.AuthExpiredMailboxes) > 0 {
333→		fmt.Fprintf(&b, "Mailbox reconnect required: %s. Guide the user to reconnect before new sends.\n", strings.Join(report.Delta.AuthExpiredMailboxes, ", "))
334→	}
335→
336→	return b.String()
337→}
