 11→func AddSuppression(d *sql.DB, scope, value, reason, source string) (*Suppression, error) {
 12→	scope = normalizeSuppressionScope(scope)
 13→	value = normalizeSuppressionValue(scope, value)
 14→	if value == "" {
 15→		return nil, fmt.Errorf("suppression value is required")
 16→	}
 17→	if source == "" {
 18→		source = "manual"
 19→	}
 20→
 21→	_, err := d.Exec(`
 22→		INSERT INTO suppressions (id, scope, value, reason, source)
 23→		VALUES (?, ?, ?, ?, ?)
 24→		ON CONFLICT(scope, value) DO UPDATE SET
 25→			reason = excluded.reason,
 26→			source = excluded.source`,
 27→		newID("sup"), scope, value, reason, source,
 28→	)
 29→	if err != nil {
 30→		return nil, err
 31→	}
 32→
 33→	return suppressionByScopeValue(d, scope, value)
 34→}
