119→func normalizeSuppressionValue(scope, value string) string {
120→	value = strings.ToLower(strings.TrimSpace(value))
121→	if scope == "domain" {
122→		value = strings.TrimPrefix(value, "@")
123→	}
124→	return value
125→}
