300→func ListReplyEvents(d *sql.DB, limit int) ([]ReplyEvent, error) {
301→	query := `SELECT id, enrollment_id, mailbox_id, thread_id, message_id, contact_email, classification, status, assigned_to, subject, snippet, draft_reply, handled_at, occurred_at FROM reply_events ORDER BY occurred_at DESC`
302→	if limit > 0 {
303→		query += fmt.Sprintf(" LIMIT %d", limit)
304→	}
305→	rows, err := d.Query(query)
306→	if err != nil {
307→		return nil, err
308→	}
309→	defer rows.Close()
310→
311→	var items []ReplyEvent
312→	for rows.Next() {
313→		var item ReplyEvent
314→		if err := rows.Scan(&item.ID, &item.EnrollmentID, &item.MailboxID, &item.ThreadID, &item.MessageID, &item.ContactEmail, &item.Classification, &item.Status, &item.AssignedTo, &item.Subject, &item.Snippet, &item.DraftReply, &item.HandledAt, &item.OccurredAt); err != nil {
315→			return nil, err
