323→func normalizeReplyClassification(classification string) string {
324→	switch strings.ToLower(strings.TrimSpace(classification)) {
325→	case "interested", "positive":
326→		return "interested"
327→	case "bounce", "bounced", "hard_bounce", "hard-bounce":
328→		return "bounced"
329→	case "unsubscribe", "opt_out", "opt-out":
330→		return "unsubscribe"
331→	case "not_interested", "negative":
332→		return "not_interested"
333→	case "out_of_office", "ooo", "away":
334→		return "out_of_office"
335→	case "referral":
336→		return "referral"
337→	default:
338→		return "replied"
339→	}
340→}
