 10→type hooksStep struct{}
 11→
 12→func (s *hooksStep) Name() string { return "Claude Code hooks installed" }
 13→
 14→// hookEntry is a single hook within a matcher group.
 15→// Exactly one of command or prompt must be set.
 16→type hookEntry struct {
 17→	command string // for type "command"
 18→	prompt  string // for type "prompt"
 19→}
 20→
 21→// hookGroup defines a matcher group with its hooks for a given event.
 22→type hookGroup struct {
 23→	event   string
 24→	matcher string
 25→	hooks   []hookEntry
 26→}
 27→
 28→// requiredHookGroups defines all hook groups nurge needs installed.
 29→// Hooks sharing the same event+matcher are grouped together (matching entire.io's pattern).
 30→var requiredHookGroups = []hookGroup{
 31→	{
 32→		event:   "PostToolUse",
 33→		matcher: "Bash",
 34→		hooks:   []hookEntry{{command: "nurge hook post-tool-use"}},
 35→	},
 36→	{
 37→		event:   "SessionStart",
 38→		matcher: "",
 39→		hooks:   []hookEntry{{command: "nurge hook session-start"}},
 40→	},
 41→	{
 42→		event:   "UserPromptSubmit",
 43→		matcher: "",
 44→		hooks:   []hookEntry{{command: "nurge hook user-prompt"}},
 45→	},
 46→	{
 47→		event:   "Stop",
 48→		matcher: "",
 49→		hooks: []hookEntry{
 50→			{command: "nurge hook stop"},
 51→			{prompt: "Before finishing, capture any new insights from this session. If you learned something about tone preferences, ICP refinements, product positioning, messaging patterns, competitor intel, or user preferences, save each as: nurge learn save --type <type> (types: tone, icp, product, pattern, preference, competitor). Only save non-obvious insights that will help future sessions. Skip if nothing new was learned. Keep each learning to 1-2 sentences."},
 52→		},
 53→	},
 54→	{
 55→		event:   "SessionEnd",
 56→		matcher: "",
 57→		hooks:   []hookEntry{{command: "nurge hook session-end"}},
 58→	},
 59→}
 60→
 61→func (s *hooksStep) Done() (bool, error) {
 62→	data, err := os.ReadFile(claudeSettingsPath())
 63→	if err != nil {
 64→		if os.IsNotExist(err) {
 65→			return false, nil
 66→		}
 67→		return false, err
 68→	}
 69→
 70→	var settings map[string]any
 71→	if err := json.Unmarshal(data, &settings); err != nil {
 72→		return false, nil
 73→	}
 74→
 75→	hooks, ok := settings["hooks"].(map[string]any)
 76→	if !ok {
 77→		return false, nil
 78→	}
 79→
 80→	for _, g := range requiredHookGroups {
 81→		for _, h := range g.hooks {
 82→			if !hookEntryExists(hooks, g.event, h) {
 83→				return false, nil
 84→			}
 85→		}
 86→	}
 87→	return true, nil
 88→}
