 90→func (s *hooksStep) Run() error {
 91→	settingsPath := claudeSettingsPath()
 92→
 93→	if err := os.MkdirAll(filepath.Dir(settingsPath), 0755); err != nil {
 94→		return fmt.Errorf("creating .claude/: %w", err)
 95→	}
 96→
 97→	// Load existing settings or start fresh
 98→	settings := make(map[string]any)
 99→	if data, err := os.ReadFile(settingsPath); err == nil {
100→		json.Unmarshal(data, &settings) // ignore error, start fresh if corrupt
101→	}
102→
103→	hooks, _ := settings["hooks"].(map[string]any)
104→	if hooks == nil {
105→		hooks = make(map[string]any)
106→	}
107→
108→	for _, g := range requiredHookGroups {
109→		// Collect entries that are missing
110→		var missing []hookEntry
111→		for _, h := range g.hooks {
112→			if !hookEntryExists(hooks, g.event, h) {
113→				missing = append(missing, h)
114→			}
115→		}
116→		if len(missing) == 0 {
117→			continue
118→		}
119→
120→		// Find existing matcher entry for this event+matcher, or create one
121→		eventHooks, _ := hooks[g.event].([]any)
122→		matcherIdx := -1
123→		for i, item := range eventHooks {
124→			m, ok := item.(map[string]any)
125→			if !ok {
126→				continue
127→			}
128→			if matcher, _ := m["matcher"].(string); matcher == g.matcher {
129→				matcherIdx = i
130→				break
131→			}
132→		}
133→
134→		if matcherIdx >= 0 {
135→			entry := eventHooks[matcherIdx].(map[string]any)
136→			innerHooks, _ := entry["hooks"].([]any)
137→			for _, h := range missing {
138→				innerHooks = append(innerHooks, hookEntryToJSON(h))
139→			}
140→			entry["hooks"] = innerHooks
141→		} else {
142→			var innerHooks []any
143→			for _, h := range g.hooks {
144→				innerHooks = append(innerHooks, hookEntryToJSON(h))
145→			}
146→			entry := map[string]any{
147→				"matcher": g.matcher,
148→				"hooks":   innerHooks,
149→			}
150→			eventHooks = append(eventHooks, entry)
151→		}
152→		hooks[g.event] = eventHooks
153→	}
154→
155→	settings["hooks"] = hooks
156→
157→	// Sync permissions into the settings
158→	syncPermissionsInto(settings)
159→
160→	data, err := json.MarshalIndent(settings, "", "  ")
161→	if err != nil {
162→		return fmt.Errorf("marshaling settings: %w", err)
163→	}
164→
165→	if err := os.WriteFile(settingsPath, data, 0644); err != nil {
166→		return fmt.Errorf("writing settings: %w", err)
167→	}
168→
169→	return nil
170→}
