172→// hookEntryExists checks if a specific hook entry (command or prompt) already
173→// exists under the given event key.
174→func hookEntryExists(hooks map[string]any, event string, entry hookEntry) bool {
175→	arr, ok := hooks[event].([]any)
176→	if !ok {
177→		return false
178→	}
179→	for _, item := range arr {
180→		m, ok := item.(map[string]any)
181→		if !ok {
182→			continue
183→		}
184→		innerHooks, ok := m["hooks"].([]any)
185→		if !ok {
186→			continue
187→		}
188→		for _, h := range innerHooks {
189→			hm, ok := h.(map[string]any)
190→			if !ok {
191→				continue
192→			}
193→			if entry.command != "" {
194→				if cmd, ok := hm["command"].(string); ok && cmd == entry.command {
195→					return true
196→				}
197→			}
198→			if entry.prompt != "" {
199→				if p, ok := hm["prompt"].(string); ok && p == entry.prompt {
200→					return true
201→				}
202→			}
203→		}
204→	}
205→	return false
206→}
207→
208→// hookCommandExists is a convenience wrapper for checking command hooks.
209→func hookCommandExists(hooks map[string]any, event, command string) bool {
210→	return hookEntryExists(hooks, event, hookEntry{command: command})
211→}
212→
213→func containsString(arr []any, s string) bool {
214→	for _, v := range arr {
215→		if str, ok := v.(string); ok && str == s {
216→			return true
217→		}
218→	}
219→	return false
220→}
221→
222→func hookEntryToJSON(entry hookEntry) map[string]any {
223→	if entry.prompt != "" {
224→		return map[string]any{"type": "prompt", "prompt": entry.prompt}
225→	}
226→	return map[string]any{"type": "command", "command": entry.command}
227→}
