229→func claudeSettingsPath() string {
230→	return filepath.Join(".claude", "settings.json")
231→}
232→
233→// RequiredPermissions lists all allow-rules nurge needs in .claude/settings.json.
234→// Kept in one place so init and session-start sync stay consistent.
235→var RequiredPermissions = []string{
236→	"Bash(nurge *)",
237→	"Bash(git *)",
238→	"Bash(go *)",
239→	"Bash(curl *)",
240→	"Bash(dig *)",
241→	"Bash(gh *)",
242→	"Bash(which *)",
243→	"Bash(ls *)",
244→	"Bash(mkdir *)",
245→	"Bash(cp *)",
246→	"Bash(mv *)",
247→	"Read",
248→	"Edit",
249→	"Write",
250→	"WebFetch",
251→	"WebSearch",
252→}
253→
254→// syncPermissionsInto ensures all RequiredPermissions are present in the
255→// given settings map (mutates in place).
256→func syncPermissionsInto(settings map[string]any) {
257→	permissions, _ := settings["permissions"].(map[string]any)
258→	if permissions == nil {
259→		permissions = make(map[string]any)
260→	}
261→	allow, _ := permissions["allow"].([]any)
262→	for _, perm := range RequiredPermissions {
263→		if !containsString(allow, perm) {
264→			allow = append(allow, perm)
265→		}
266→	}
267→	permissions["allow"] = allow
268→	settings["permissions"] = permissions
269→}
270→
271→// SyncPermissions reads .claude/settings.json, adds any missing required
272→// permissions, and writes the file back. Safe to call on every session start.
273→// Returns (added, error) where added is the number of new permissions inserted.
274→func SyncPermissions() (int, error) {
275→	settingsPath := claudeSettingsPath()
276→
277→	settings := make(map[string]any)
278→	if data, err := os.ReadFile(settingsPath); err == nil {
279→		json.Unmarshal(data, &settings)
280→	} else if os.IsNotExist(err) {
281→		return 0, nil
282→	} else {
283→		return 0, err
284→	}
285→
286→	before := countAllowPermissions(settings)
287→	syncPermissionsInto(settings)
288→	added := countAllowPermissions(settings) - before
289→	if added == 0 {
290→		return 0, nil
291→	}
292→
293→	data, err := json.MarshalIndent(settings, "", "  ")
294→	if err != nil {
295→		return 0, fmt.Errorf("marshaling settings: %w", err)
296→	}
297→	if err := os.WriteFile(settingsPath, data, 0644); err != nil {
298→		return 0, fmt.Errorf("writing settings: %w", err)
299→	}
300→	return added, nil
301→}
302→
303→func countAllowPermissions(settings map[string]any) int {
304→	permissions, _ := settings["permissions"].(map[string]any)
305→	if permissions == nil {
306→		return 0
307→	}
308→	allow, _ := permissions["allow"].([]any)
309→	return len(allow)
310→}
